      requiredCredentials: ["WORKFORCE_JOBS_WEBHOOK_URL", "WORKFORCE_JOBS_API_KEY", "WORKFORCE_CALENDAR_WEBHOOK_URL", "WORKFORCE_HRIS_API_KEY"],
