async function translateDynamicContent(db, user, { text, targetLanguage, sourceLanguage = "en", context = "platform" }) {
  const runtime = providerRuntime("translation");
  let translatedText = localTranslateText(text, targetLanguage);
  let provider = "local-dictionary";
  if (runtime.mode !== "local-dictionary" && runtime.mode !== "sandbox" && runtime.webhookUrl && runtime.apiKey) {
    try {
      const response = await fetchWithTimeout(runtime.webhookUrl, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          authorization: `Bearer ${runtime.apiKey}`
        },
        body: JSON.stringify({ text, sourceLanguage, targetLanguage, context, userId: user.id })
      }, PROVIDER_WEBHOOK_TIMEOUT_MS);
      const json = await response.json().catch(() => ({}));
      if (response.ok && json.translatedText) {
        translatedText = json.translatedText;
        provider = json.provider || runtime.mode;
      }
    } catch (error) {
      provider = "local-after-translation-error";
    }
  }
  if ((provider === "local-dictionary" || provider === "local-after-translation-error") && process.env.OPENAI_API_KEY && targetLanguage && targetLanguage !== sourceLanguage) {
    try {
      const response = await fetchWithTimeout("https://api.openai.com/v1/responses", {
        method: "POST",
        headers: {
          "content-type": "application/json",
          Authorization: `Bearer ${process.env.OPENAI_API_KEY}`
        },
        body: JSON.stringify({
          model: AI_TRANSLATION_MODEL,
          input: [
            {
              role: "system",
              content: [
                "Translate the user's content for AgriNexus.",
                "Preserve product names, button labels, IDs, safety meaning, and workflow intent.",
                "Return only the translated text.",
                "Use plain language suitable for rural, low-tech users."
              ].join(" ")
            },
            {
              role: "user",
              content: JSON.stringify({ text, sourceLanguage, targetLanguage, context })
            }
          ],
          max_output_tokens: 600
        })
      }, PROVIDER_WEBHOOK_TIMEOUT_MS);
      const json = await response.json().catch(() => ({}));
      if (response.ok) {
        const openAiText = extractResponseText(json);
        if (openAiText) {
          translatedText = openAiText;
          provider = "openai-translation";
        }
      }
    } catch (error) {
      provider = "local-after-openai-translation-error";
    }
  }
  logIntegration(db, {
    providerId: "translation",
    module: "AI",
    action: "translation.dynamic",
    detail: `Translated ${context} content to ${targetLanguage}.`,
    metadata: { sourceLanguage, targetLanguage, provider }
  });
  return { sourceText: text, translatedText, sourceLanguage, targetLanguage, provider };
}

const TRANSLATED_DISPLAY_KEYS = new Set([
  "response", "title", "label", "helper", "summary", "detail", "description", "message", "reason",
  "action", "nextAction", "nextQuestion", "prompt", "rule", "frame", "userModeRule", "adminModeRule",
  "investorModeRule", "statusText", "module", "priority", "goal", "productName", "buyerLocation",
  "sellerLocation", "routeName", "checkpoint", "providerStatus", "mapProviderStatus",
  "logisticsProviderStatus", "unclearSpeech", "providerFailure", "safetyEscalation",
  "offlineOrSlowNetwork", "stopCommand", "localNow", "liveLater", "name", "engine", "missing",
  "suggestedReplies", "nextSteps", "boundaries", "reliabilityContract", "nextGaps", "liveGaps",
  "steps", "commands", "suggestedCommands", "actions", "options"
]);

const STABLE_DISPLAY_KEYS = new Set([
  "id", "mode", "intent", "type", "tool", "role", "email", "createdBy", "createdAt", "updatedAt",
  "packetNumber", "packetId", "routeId", "countryId", "providerId", "moduleId", "section",
  "redirectSection", "sourceLanguage", "targetLanguage", "provider", "providerReady", "connected",
  "permissions", "origin", "destination", "coordinates", "lat", "lng", "latitude", "longitude",
  "distanceKm", "confidence", "score", "ready", "readyCount", "total", "liveRoutingConfigured",
  "liveRoutingReady", "gpsTrackingReady", "confirmationRequired", "createdAt"
]);

function shouldTranslateDisplayString(key, value) {
  const text = String(value || "").trim();
  if (!text) return false;
  if (STABLE_DISPLAY_KEYS.has(key)) return false;
  if (/\b[A-Z0-9]{8,}-[A-Z0-9-]{4,}\b/i.test(text)) return false;
  if (/^https?:\/\//i.test(text)) return false;
  if (/^[a-z0-9_.:-]+$/i.test(text) && !text.includes(" ")) return false;
  return TRANSLATED_DISPLAY_KEYS.has(key) || /Rule$|Text$|Summary$|Reason$|Message$|Action$|Question$/i.test(key);
}

async function translateDisplayValue(db, user, value, targetLanguage, context, cache, budget, key = "") {
  if (!targetLanguage || targetLanguage === "en") return value;
  if (typeof value === "string") {
    if (!shouldTranslateDisplayString(key, value)) return value;
    const cacheKey = `${targetLanguage}:${value}`;
    if (cache.has(cacheKey)) return cache.get(cacheKey);
    if (budget.count >= budget.max) return value;
    budget.count += 1;
    const translation = await translateDynamicContent(db, user, {
      text: value,
      sourceLanguage: "en",
      targetLanguage,
      context
    });
    const translated = translation.translatedText || value;
    cache.set(cacheKey, translated);
    return translated;
  }
  if (Array.isArray(value)) {
    const translated = [];
    for (const item of value) {
      translated.push(await translateDisplayValue(db, user, item, targetLanguage, context, cache, budget, key));
    }
    return translated;
  }
  if (value && typeof value === "object") {
    const translated = {};
    for (const [childKey, childValue] of Object.entries(value)) {
      if (STABLE_DISPLAY_KEYS.has(childKey)) {
        translated[childKey] = childValue;
      } else {
        translated[childKey] = await translateDisplayValue(db, user, childValue, targetLanguage, `${context}:${childKey}`, cache, budget, childKey);
      }
    }
    return translated;
  }
  return value;
}

async function translateAgentDisplayBundle(db, user, result = {}, targetLanguage = "en") {
  if (!targetLanguage || targetLanguage === "en") return null;
  const metadata = result.metadata || {};
  const displayBundle = {
    response: result.response || "",
    suggestedReplies: metadata.suggestedReplies || [],
    turnCoach: metadata.turnCoach || null,
    situationAgent: metadata.situationAgent || null,
    preProviderHardening: metadata.preProviderHardening || null,
    packet: metadata.packet || null,
    missionBrain: metadata.missionBrain || null,
    trustedOperatingSystem: metadata.trustedOperatingSystem || null,
    voiceMission: metadata.voiceMission || null
  };
  const cache = new Map();
  const budget = { count: 0, max: 90 };
  const localized = await translateDisplayValue(db, user, displayBundle, targetLanguage, `agent-display:${result.intent || "unknown"}`, cache, budget);
  return {
    ...localized,
    translationBudgetUsed: budget.count,
    preservedSystemFields: true
  };
}

async function translateAgentCommandResult(db, user, result = {}, options = {}) {
  const targetLanguage = options.targetLanguage || user?.language || db.profile.accessibilityProfile?.language || "en";
  if (!targetLanguage || targetLanguage === "en" || !result.response) return result;
  const translation = await translateDynamicContent(db, user, {
    text: result.response,
    sourceLanguage: "en",
    targetLanguage,
    context: `agent-command:${result.intent || "unknown"}`
  });
  const translatedResult = {
    ...result,
    response: translation.translatedText || result.response
  };
  const localized = await translateAgentDisplayBundle(db, user, translatedResult, targetLanguage);
  return {
    ...translatedResult,
    metadata: {
      ...(result.metadata || {}),
      originalResponse: result.response,
      translatedResponse: true,
      translatedDisplay: true,
      localized,
      translation: {
        targetLanguage,
        sourceLanguage: "en",
        provider: translation.provider,
        context: `agent-command:${result.intent || "unknown"}`
      }
    }
  };
}

async function executeAgentPlanObject(db, user, plan, note = "Approved from command center") {
  plan.status = "executing";
  plan.approvedBy = user.email;
  plan.approvedAt = new Date().toISOString();
  plan.executedBy = user.email;
  plan.executedAt = new Date().toISOString();
  const executedSteps = [];
  for (const step of plan.steps) {
    executedSteps.push(await executeAgentStepWithRetry(db, user, step, 2));
  }
  plan.steps = executedSteps;
  const failedSteps = executedSteps.filter(step => step.status === "failed");
  plan.status = failedSteps.length ? "needs-review" : "executed";
  const execution = {
    id: crypto.randomUUID(),
    planId: plan.id,
    goal: plan.goal,
    status: failedSteps.length ? "needs-review" : "completed",
    summary: failedSteps.length
      ? `Agent executed ${executedSteps.length - failedSteps.length}/${executedSteps.length} supervised steps; ${failedSteps.length} need operator review.`
      : `Agent autonomously executed ${executedSteps.length} supervised steps across learning, workforce, health, trade, maps, and AI.`,
    steps: executedSteps.map(step => ({ module: step.module, tool: step.tool, action: step.action, status: step.status, attempts: step.attempts, result: step.result, error: step.error })),
    note,
    createdAt: new Date().toISOString()
  };
  db.profile.agentExecutions.unshift(execution);
  db.profile.agentExecutions = db.profile.agentExecutions.slice(0, 20);
  db.profile.agentMemory = {
    ...(db.profile.agentMemory || {}),
    lastPlanId: plan.id,
    lastExecutionId: execution.id,
    lastGoal: plan.goal,
    lastStatus: execution.status,
    lastSummary: execution.summary,
    lastSteps: execution.steps.map(step => ({ module: step.module, action: step.action, status: step.status })),
    updatedAt: new Date().toISOString()
  };
  addActivity(db.profile, execution.summary);
  return execution;
}

function commandGoal(command) {
  return command
    .replace(/^(please\s+)?(create|build|make|generate)\s+(an?\s+)?(agent\s+)?plan( for| to)?/i, "")
    .replace(/^(please\s+)?plan( for| to)?/i, "")
    .trim();
}

function addConversationTurn(profile, role, text, metadata = {}) {
  ensureAiProfile(profile);
  if (!String(text || "").trim()) return null;
  const turn = {
    id: crypto.randomUUID(),
    role,
    text: String(text || "").trim(),
    metadata,
    createdAt: new Date().toISOString()
  };
  profile.agentConversation.push(turn);
  profile.agentConversation = profile.agentConversation.slice(-50);
  return turn;
}

function inferMemoryCategory(text) {
  const lower = String(text || "").toLowerCase();
  if (lower.includes("prefer") || lower.includes("i like") || lower.includes("i want") || lower.includes("always") || lower.includes("don't") || lower.includes("do not")) return "preference";
  if (lower.includes("because") || lower.includes("next time") || lower.includes("when ") || lower.includes("after ")) return "pattern";
  if (lower.includes("emergency") || lower.includes("doctor") || lower.includes("diagnose") || lower.includes("medicine") || lower.includes("payment") || lower.includes("consent")) return "safety";
  return "fact";
}

function memoryBucket(profile, category) {
  ensureAiProfile(profile);
  if (category === "preference") return profile.agentMemory.preferences;
  if (category === "pattern") return profile.agentMemory.learnedPatterns;
  if (category === "safety") return profile.agentMemory.safetyBoundaries;
  return profile.agentMemory.longTermFacts;
}

function normalizeMemoryText(text) {
  return String(text || "").trim().toLowerCase().replace(/\s+/g, " ");
}

function memoryModuleForText(text, metadata = {}) {
  if (metadata.module) return metadata.module;
  const signal = conversationModuleSignal(text);
  return signal.module === "Platform" ? (metadata.category === "safety" ? "Safety" : "Platform") : signal.module;
}

function memoryNeedSignals(text) {
  const lower = String(text || "").toLowerCase();
  const needs = [];
  if (/\bvoice|speak|talk|listen|microphone|audio|read aloud\b/.test(lower)) needs.push("voice-first");
  if (/\bcaption|captions|deaf|hearing|hard of hearing|transcript\b/.test(lower)) needs.push("hearing-support");
  if (/\bblind|visual|large print|screen reader|bad vision|visually impaired\b/.test(lower)) needs.push("visual-support");
  if (/\bsimple|easy|grandma|non technical|non-technical|low tech|low-tech|plain language\b/.test(lower)) needs.push("plain-language");
  if (/\boffline|low bandwidth|poor internet|bad internet|rural signal\b/.test(lower)) needs.push("low-bandwidth");
  if (/\bfarmer|crop|field|harvest|plant|drone|buyer|sell\b/.test(lower)) needs.push("farmer-operations");
  if (/\bpatient|care|provider|clinic|telehealth|injury|outbreak|ebola\b/.test(lower)) needs.push("care-access");
  if (/\blearner|student|course|lesson|training|certificate\b/.test(lower)) needs.push("learning-support");
  if (/\bjob|apply|role|workforce|shift|mentor|interview\b/.test(lower)) needs.push("workforce-support");
  return [...new Set(needs)];
}

function updateStructuredLongTermMemory(profile, item, metadata = {}) {
  ensureAiProfile(profile);
  const moduleName = item.module || memoryModuleForText(item.text, metadata);
  const needs = item.needs || memoryNeedSignals(item.text);
  item.module = moduleName;
  item.needs = needs;
  item.tags = [...new Set([item.category, moduleName, ...needs].filter(Boolean).map(value => String(value).toLowerCase().replace(/\s+/g, "-")))].slice(0, 8);

  const moduleBucket = profile.agentMemory.moduleMemory[moduleName] || [];
  const existingModule = moduleBucket.find(memory => memory.normalized === item.normalized);
  const moduleItem = {
    id: item.id,
    category: item.category,
    text: item.text,
    normalized: item.normalized,
    source: item.source,
    confidence: item.confidence,
    tags: item.tags,
    needs,
    uses: item.uses,
    updatedAt: item.updatedAt
  };
  profile.agentMemory.moduleMemory[moduleName] = existingModule
    ? moduleBucket.map(memory => memory.normalized === item.normalized ? { ...memory, ...moduleItem, uses: Number(memory.uses || 0) + 1 } : memory).slice(0, 20)
    : [moduleItem, ...moduleBucket].slice(0, 20);

  needs.forEach(need => {
    const needBucket = profile.agentMemory.userNeeds[need] || [];
    profile.agentMemory.userNeeds[need] = [{ id: item.id, module: moduleName, text: item.text, confidence: item.confidence, updatedAt: item.updatedAt }, ...needBucket.filter(memory => memory.id !== item.id)].slice(0, 12);
  });

  if (!metadata.noTimeline && metadata.source && /advisor|workflow|intake|conversation|trade|health|learning|workforce|drone|route/i.test(metadata.source)) {
    profile.agentMemory.advisorHistory = [{
      id: crypto.randomUUID(),
      memoryId: item.id,
      module: moduleName,
      event: item.text,
      source: item.source,
      confidence: item.confidence,
      createdAt: item.updatedAt
    }, ...(profile.agentMemory.advisorHistory || [])].slice(0, 50);
  }

  if (!metadata.noTimeline) {
    profile.agentMemory.memoryTimeline = [{
      id: crypto.randomUUID(),
      type: item.category,
      module: moduleName,
      title: item.text.length > 90 ? `${item.text.slice(0, 87)}...` : item.text,
      source: item.source,
      tags: item.tags,
      createdAt: item.updatedAt
    }, ...(profile.agentMemory.memoryTimeline || [])].slice(0, 80);
  }
  return item;
}

function rememberAgentMemory(profile, text, metadata = {}) {
  ensureAiProfile(profile);
  const value = String(text || "").trim();
  if (!value) return null;
  const category = metadata.category || inferMemoryCategory(value);
  const bucket = memoryBucket(profile, category);
  const normalized = normalizeMemoryText(value);
  const existing = bucket.find(item => item.normalized === normalized);
  if (existing) {
    existing.uses = Number(existing.uses || 0) + 1;
    existing.updatedAt = new Date().toISOString();
    existing.source = metadata.source || existing.source;
    existing.module = existing.module || memoryModuleForText(value, metadata);
    existing.needs = existing.needs || memoryNeedSignals(value);
    return updateStructuredLongTermMemory(profile, existing, { ...metadata, noTimeline: true });
  }
  const item = {
    id: crypto.randomUUID(),
    category,
    text: value,
    normalized,
    module: memoryModuleForText(value, metadata),
    needs: memoryNeedSignals(value),
    source: metadata.source || "agent-command",
    confidence: Number(metadata.confidence || 0.78),
    uses: 1,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  bucket.unshift(item);
  if (category === "preference") profile.agentMemory.preferences = bucket.slice(0, 30);
  else if (category === "pattern") profile.agentMemory.learnedPatterns = bucket.slice(0, 30);
  else if (category === "safety") profile.agentMemory.safetyBoundaries = bucket.slice(0, 30);
  else profile.agentMemory.longTermFacts = bucket.slice(0, 40);
  profile.agentMemory.updatedAt = item.updatedAt;
  return updateStructuredLongTermMemory(profile, item, metadata);
}

function retrieveAgentMemories(profile, query, limit = 6) {
  ensureAiProfile(profile);
  const queryTokens = new Set(tokenizeAgentText(query));
  const queryModule = memoryModuleForText(query);
  const queryNeeds = new Set(memoryNeedSignals(query));
  const all = [
    ...(profile.agentMemory.preferences || []),
    ...(profile.agentMemory.learnedPatterns || []),
    ...(profile.agentMemory.longTermFacts || []),
    ...(profile.agentMemory.safetyBoundaries || []),
    ...Object.values(profile.agentMemory.moduleMemory || {}).flat(),
    ...(profile.agentMemory.advisorHistory || []).map(item => ({ ...item, text: item.event, category: "advisor-history", confidence: item.confidence || 0.66 })),
    ...(profile.agentMemory.rememberedContexts || []).map(item => ({ ...item, text: `${item.command || ""} ${item.intent || ""} ${item.response || ""}`, category: "recent-context", confidence: 0.62 }))
  ];
  const unique = new Map();
  all.filter(Boolean).forEach(item => {
    const key = item.id || normalizeMemoryText(item.text || item.command || item.response || "");
    if (!unique.has(key)) unique.set(key, item);
  });
  const scored = [...unique.values()]
    .map(item => {
      const tokens = tokenizeAgentText(item.text || item.command || item.response || "");
      const overlap = tokens.reduce((total, token) => total + (queryTokens.has(token) ? 1 : 0), 0);
      const needBoost = (item.needs || []).reduce((total, need) => total + (queryNeeds.has(need) ? 0.75 : 0), 0);
      const moduleBoost = item.module && item.module === queryModule ? 0.8 : 0;
      return { ...item, score: overlap + needBoost + moduleBoost + Number(item.uses || 0) * 0.15 + Number(item.confidence || 0) * 0.25 };
    })
    .filter(item => item.score > 0.35)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
  profile.agentMemory.retrievals.unshift({
    id: crypto.randomUUID(),
    query,
    memoryIds: scored.map(item => item.id).filter(Boolean),
    createdAt: new Date().toISOString()
  });
  profile.agentMemory.retrievals = profile.agentMemory.retrievals.slice(0, 20);
  return scored;
}

function longTermMemorySummary(profile) {
  ensureAiProfile(profile);
  const memory = profile.agentMemory;
  const moduleNames = Object.keys(memory.moduleMemory || {});
  const needNames = Object.keys(memory.userNeeds || {});
  const core = [
    ...(memory.preferences || []),
    ...(memory.learnedPatterns || []),
    ...(memory.longTermFacts || []),
    ...(memory.safetyBoundaries || [])
  ];
  const preferred = (memory.preferences || []).slice(0, 3);
  const preferredIds = new Set(preferred.map(item => item.id));
  const topMemories = [
    ...preferred,
    ...core
      .filter(item => !preferredIds.has(item.id))
      .sort((a, b) => String(b.updatedAt || "").localeCompare(String(a.updatedAt || "")))
  ].slice(0, 5);
  const summary = {
    total: core.length,
    modules: moduleNames.map(name => ({ name, count: (memory.moduleMemory[name] || []).length })).sort((a, b) => b.count - a.count),
    needs: needNames.map(name => ({ name, count: (memory.userNeeds[name] || []).length })).sort((a, b) => b.count - a.count),
    advisorEvents: (memory.advisorHistory || []).length,
    timeline: (memory.memoryTimeline || []).slice(0, 8),
    topMemories
  };
  memory.lastMemorySummary = summary.total
    ? `I remember ${summary.total} long-term item(s), ${summary.modules.length} module area(s), and ${summary.needs.length} user need signal(s).`
    : "No durable long-term memory has been saved yet.";
  return summary;
}

function aiReasoningSnapshot(db, user, command, moduleSignal, memories = [], options = {}) {
  const { country, route } = activeContext(db);
  const text = String(command || "").trim();
  const lower = text.toLowerCase();
  const memorySummary = longTermMemorySummary(db.profile);
  const moduleName = moduleSignal?.module || conversationModuleSignal(text).module;
  const actionLikely = isActionRequest(lower);
  const sensitive = /\b(emergency|injury|doctor|medicine|diagnose|payment|wallet|apply|provider|call|message|consent|outbreak|ebola)\b/.test(lower);
  const userNeeds = [
    ...(db.profile.agentMemory.userModel?.accessibilityMode && db.profile.agentMemory.userModel.accessibilityMode !== "standard" ? [db.profile.agentMemory.userModel.accessibilityMode] : []),
    ...(db.profile.agentMemory.userModel?.communicationStyle ? [db.profile.agentMemory.userModel.communicationStyle] : []),
    ...Object.keys(db.profile.agentMemory.userNeeds || {}).slice(0, 4)
  ].filter(Boolean);
  const optionsConsidered = [
    actionLikely ? "Run or stage the matching workflow" : "Answer conversationally first",
    memories.length ? "Use remembered user context" : "Proceed without saved memory",
    sensitive ? "Require confirmation and keep human review" : "Give the simplest next step",
    moduleName === "Healthcare" ? "Avoid diagnosis and focus on access, triage, referral, and emergency guidance" : null,
    moduleName === "AgriTrade" ? "Connect crop, buyer, route, order, payment, and delivery evidence" : null
  ].filter(Boolean);
  const reasoning = {
    id: crypto.randomUUID(),
    command: text,
    module: moduleName,
    section: moduleSignal?.section || sectionForAgentModule(moduleName),
    country: country.name,
    route: route.name,
    intentType: actionLikely ? "action-request" : "conversation",
    riskLevel: sensitive ? "confirmation-required" : "low",
    userNeeds: [...new Set(userNeeds)].slice(0, 6),
    memoryUsed: memories.slice(0, 5).map(item => ({
      id: item.id,
      category: item.category,
      module: item.module,
      text: item.text || item.event || item.response || item.command,
      confidence: item.confidence
    })),
    optionsConsidered,
    recommendation: actionLikely
      ? `Stage the safest ${moduleName} workflow and ask for confirmation before changing records or contacting anyone.`
      : `Answer in plain language, use remembered context, and offer one next step in ${moduleName}.`,
    why: [
      `${moduleName} is the strongest match for the request.`,
      memories.length ? `${memories.length} memory cue(s) can personalize the response.` : "No saved memory is required for this request.",
      sensitive ? "The request may affect health, money, jobs, providers, or messages, so confirmation is safer." : "The request can be handled with guidance or a low-risk local workflow.",
      `Current operating context is ${country.name} on ${route.name}.`
    ],
    memorySummary: {
      total: memorySummary.total,
      modules: memorySummary.modules.slice(0, 4),
      needs: memorySummary.needs.slice(0, 5)
    },
    createdAt: new Date().toISOString()
  };
  db.profile.agentMemory.reasoningHistory = [reasoning, ...(db.profile.agentMemory.reasoningHistory || [])].slice(0, 40);
  db.profile.agentMemory.lastReasoning = reasoning;
  db.profile.agentMemory.updatedAt = reasoning.createdAt;
  return reasoning;
}

function roleSpecificReasoningProfile(moduleName = "Agent AI", userModel = {}) {
  const persona = userModel.currentPersona || "general-operator";
  const profiles = {
    "farmer-or-trade-operator": {
      audience: "farmer or crop seller",
      style: "field-first, buyer-aware, simple business language",
      priorities: ["protect crop quality", "reduce route risk", "verify buyer terms", "explain drone evidence simply", "confirm payment before release"],
      nextQuestion: "What crop are you working with, and what are you trying to do first?"
    },
    "health-access-user": {
      audience: "patient, caregiver, or health aide",
      style: "safety-first, consent-aware, calm plain language",
      priorities: ["check danger signs", "avoid diagnosis", "capture consent", "support captions/audio/caregiver", "connect provider or emergency help"],
      nextQuestion: "What happened, where is the person, and are they safe right now?"
    },
    learner: {
      audience: "student or learner",
      style: "encouraging, small-step, low-literacy friendly",
      priorities: ["explain one idea", "offer captions/audio", "complete one lesson step", "save progress", "connect certificate to work"],
      nextQuestion: "What lesson or skill are you trying to understand today?"
    },
    "workforce-candidate": {
      audience: "worker or job seeker",
      style: "practical, readiness-focused, confidence-building",
      priorities: ["find role", "check documents and skills", "apply safely", "prepare interview", "plan shift and transport"],
      nextQuestion: "Are you trying to find a job, apply now, prepare documents, or get ready for an interview?"
    },
    "general-operator": {
      audience: "rural platform user",
      style: "warm, direct, voice-first, one step at a time",
      priorities: ["understand intent", "choose safest module", "ask only one question if unclear", "stage actions before execution", "explain evidence"],
      nextQuestion: "What do you want Nexus to help you do first?"
    }
  };
  const selected = profiles[persona] || profiles["general-operator"];
  return {
    ...selected,
    module: moduleName,
    persona,
    language: userModel.lastRequestedLanguage || "profile-language",
    accessibility: userModel.accessibilityMode || "standard",
    connectivity: userModel.connectivityMode || "standard"
  };
}

function evidenceForReasoning(db, moduleName = "Agent AI") {
  const { country, route } = activeContext(db);
  const evidence = [
    `${country.name} active country, ${route.name} active route, checkpoint ${db.profile.activeCheckpoint}`,
    `${db.profile.readiness || 0}% workforce readiness`,
    `${(db.profile.enrollments || []).length} enrollment(s), ${(db.profile.certificates || []).length} certificate(s)`,
    `${(db.profile.healthIntakes || []).length} health intake(s), ${(db.profile.videoSessions || []).length} video session(s)`,
    `${(db.profile.orders || []).length} trade order(s), ${(db.profile.droneScans || []).length} drone scan(s)`,
    `${(db.profile.integrationEvents || []).length} provider/audit event(s)`
  ];
  if (moduleName === "Healthcare") evidence.push(`${country.risk} regional health risk; ${country.queue} queue context`);
  if (moduleName === "AgriTrade") evidence.push(`${db.profile.wallet || 0} wallet balance; route stage ${db.profile.routeStage}`);
  if (moduleName === "Learning") evidence.push(`Active course ${db.profile.activeCourseId || "none"}`);
  if (moduleName === "Workforce") evidence.push(`Candidate stage ${db.profile.candidateStage || "not started"}`);
  return evidence;
}

function reasoningLanguageProductionEngine(db, user, command = "", options = {}) {
  ensureAiProfile(db.profile);
  const moduleSignal = options.moduleSignal || conversationModuleSignal(command);
  const memories = options.memories || retrieveAgentMemories(db.profile, command, 6);
  const reasoning = options.reasoning || aiReasoningSnapshot(db, user, command, moduleSignal, memories, options);
  const userModel = db.profile.agentMemory.userModel || {};
  const targetLanguage = options.targetLanguage || user?.language || db.profile.accessibilityProfile?.language || userModel.lastRequestedLanguage || "en";
  const roleProfile = roleSpecificReasoningProfile(moduleSignal.module, userModel);
  const providers = runtimeProviders(db);
  const providerOk = id => {
    const provider = providers.find(item => item.id === id);
    return ["connected", "ready"].includes(provider?.status) || ["openai", "translation"].includes(id) && Boolean(process.env.OPENAI_API_KEY);
  };
  const layers = [
    { id: "live-reasoning-engine", title: "Live Reasoning Engine", ready: Boolean(process.env.OPENAI_API_KEY || process.env.AI_WEBHOOK_URL), evidence: process.env.OPENAI_API_KEY ? `OpenAI reasoning model ${AI_REASONING_MODEL} configured.` : process.env.AI_WEBHOOK_URL ? "AI webhook configured." : "Local reasoning scaffold active until live AI credentials are present." },
    { id: "real-translation-engine", title: "Real Translation Engine", ready: Boolean(providerOk("translation") || process.env.OPENAI_API_KEY), evidence: providerOk("translation") ? "Translation provider connected." : process.env.OPENAI_API_KEY ? `OpenAI translation fallback through ${AI_TRANSLATION_MODEL}.` : "Local dictionary fallback active." },
    { id: "conversation-memory-upgrade", title: "Conversation Memory Upgrade", ready: Boolean((db.profile.agentMemory.longTermFacts || []).length || (db.profile.agentMemory.preferences || []).length || (db.profile.agentConversation || []).length), evidence: `${(db.profile.agentMemory.longTermFacts || []).length + (db.profile.agentMemory.preferences || []).length + (db.profile.agentMemory.learnedPatterns || []).length} durable memory item(s), ${(db.profile.agentConversation || []).length} conversation turn(s).` },
    { id: "reasoning-before-action", title: "Reasoning Before Action", ready: true, evidence: `Pre-action reasoning says: ${reasoning.recommendation}` },
    { id: "multilingual-voice-brain", title: "Multilingual Voice Brain", ready: Boolean(providerOk("voice-stt") || providerOk("voice-tts") || process.env.OPENAI_API_KEY), evidence: `Target language ${targetLanguage}; STT/TTS providers tracked with browser and OpenAI fallbacks.` },
    { id: "role-specific-intelligence", title: "Role-Specific Intelligence", ready: true, evidence: `${roleProfile.audience}: ${roleProfile.priorities.slice(0, 3).join(", ")}.` },
    { id: "human-like-recovery", title: "Human-Like Recovery", ready: true, evidence: "Clarification, voice recovery, imperfect-language routing, and one-question follow-up are active." },
    { id: "evidence-based-reasoning", title: "Evidence-Based Reasoning", ready: true, evidence: evidenceForReasoning(db, moduleSignal.module).slice(0, 4).join(" | ") }
  ];
  const readyCount = layers.filter(item => item.ready).length;
  const engine = {
    id: crypto.randomUUID(),
    title: "Reasoning And Language Production Engine",
    status: readyCount >= 7 ? "production-strong" : "provider-ready",
    readyCount,
    total: layers.length,
    targetLanguage,
    module: moduleSignal.module,
    section: moduleSignal.section,
    roleProfile,
    reasoningId: reasoning.id,
    layers,
    nextQuestion: roleProfile.nextQuestion,
    createdAt: new Date().toISOString()
  };
  db.profile.agentMemory.reasoningLanguageEngine = engine;
  db.profile.agentMemory.lastReasoningLanguageProduction = engine;
  db.profile.agentMemory.reasoningLanguageHistory = [engine, ...(db.profile.agentMemory.reasoningLanguageHistory || [])].slice(0, 30);
  db.profile.agentMemory.updatedAt = engine.createdAt;
  return engine;
}

function backendAdvisorProfile(user, moduleSignal = { module: "Platform", section: "dashboard" }) {
  const role = String(user?.role || "Standard User").toLowerCase();
  const module = moduleSignal.module || "Platform";
  const persona = role.includes("admin") ? "platform operator"
    : role.includes("investor") ? "investor reviewer"
      : module === "Healthcare" ? "patient or caregiver"
        : module === "AgriTrade" || module === "Maps" ? "farmer or market user"
          : module === "Workforce" ? "worker"
            : module === "Learning" ? "learner"
              : "everyday user";
  const style = role.includes("admin") ? "risk-first, operational, evidence-based"
    : role.includes("investor") ? "impact-first, proof-first, non-technical"
      : "plain language, one step at a time, voice-first";
  return {
    persona,
    style,
    module,
    section: moduleSignal.section,
    goal: module === "Healthcare" ? "guide safe telehealth support without diagnosis"
      : module === "AgriTrade" ? "move crops from seller to buyer with communication, route, and payment evidence"
        : module === "Workforce" ? "help the user find, apply, and prepare for work"
          : module === "Learning" ? "help the learner choose, complete, understand, and prove training"
            : "route the user to the safest useful workflow",
    guardrail: module === "Healthcare" ? "confirm before health records and direct urgent danger to local emergency support"
      : module === "AgriTrade" ? "confirm before buyer, seller, money, route, or delivery actions"
        : "confirm before important records or messages"
  };
}

function backendProviderGroupReadiness(providers = runtimeProviders({ profile: {} }), ids = []) {
  const providerReady = id => ["connected", "ready"].includes(providers.find(provider => provider.id === id)?.status);
  return { ready: ids.filter(providerReady).length, total: ids.length };
}

function backendLiveKnowledgeFeedReadiness(db) {
  const providers = runtimeProviders(db);
  const providerReady = id => ["connected", "ready"].includes(providers.find(provider => provider.id === id)?.status);
  const feeds = [
    { id: "weather", title: "Weather and heat", ready: providerReady("weather") || providerReady("map-tiles"), value: "walking, planting, harvest, and field-risk guidance" },
    { id: "health", title: "Health/outbreak alerts", ready: providerReady("health-telehealth") || providerReady("health-ehr"), value: "regional telehealth safety and referral context" },
    { id: "market", title: "Crop prices and buyers", ready: providerReady("trade-market"), value: "buyer matching, price comparison, and sale timing" },
    { id: "jobs", title: "Job listings", ready: providerReady("workforce-jobs"), value: "live role search and application support" },
    { id: "courses", title: "Course catalog", ready: providerReady("learning-courses"), value: "real course selection and completion paths" },
    { id: "drone", title: "Drone/satellite evidence", ready: providerReady("field-drones"), value: "field condition interpretation and intervention planning" },
    { id: "logistics", title: "Logistics and routing", ready: providerReady("trade-logistics") || providerReady("map-tiles"), value: "delivery tracking, route risk, and facility routing" },
    { id: "communications", title: "SMS/WhatsApp/phone", ready: providerReady("sms-delivery") || providerReady("whatsapp-delivery") || providerReady("phone-voice"), value: "two-way buyer, provider, and learner communication" }
  ];
  return { ready: feeds.filter(feed => feed.ready).length, total: feeds.length, feeds };
}

function backendDecisionScoringModel(db, user, command = "") {
  const moduleSignal = conversationModuleSignal(command);
  const providers = runtimeProviders(db);
  const providerGroups = {
    Healthcare: ["health-telehealth", "health-ehr", "health-notifications"],
    AgriTrade: ["trade-market", "trade-logistics", "trade-payments", "field-drones"],
    Maps: ["trade-logistics", "map-tiles"],
    Workforce: ["workforce-jobs", "workforce-calendar", "workforce-notifications", "workforce-hris", "workforce-shifts"],
    Learning: ["learning-courses", "learning-certificates"],
    "Agent AI": ["openai", "voice-stt", "voice-tts", "phone-voice"]
  };
  const group = backendProviderGroupReadiness(providers, providerGroups[moduleSignal.module] || ["openai"]);
  const liveReadiness = group.total ? Math.round((group.ready / group.total) * 100) : 50;
  const advisor = backendAdvisorProfile(user, moduleSignal);
  const next = smartNextActions(db, user, providers).items.find(item => item.section === moduleSignal.section) || smartNextActions(db, user, providers).items[0];
  const confidence = Math.min(99, Math.round(62 + (moduleSignal.score || 0) * 8 + liveReadiness * .18));
  const safety = moduleSignal.module === "Healthcare" ? 92 : moduleSignal.module === "AgriTrade" ? 84 : 88;
  const usefulness = Math.min(98, Math.round(68 + liveReadiness * .16 + (next ? 10 : 0)));
  const score = Math.round((confidence * .36) + (usefulness * .34) + (safety * .2) + (liveReadiness * .1));
  return {
    moduleSignal,
    advisor,
    confidence,
    safety,
    usefulness,
    liveReadiness,
    score,
    recommendation: next?.title || "Ask Nexus what should happen next",
    command: next?.command || "what should I do next",
    why: `Matched ${moduleSignal.module}, used ${advisor.persona} behavior, checked live readiness ${liveReadiness}%, and weighted safety ${safety}%.`
  };
}

function backendPredictiveAdvisorModel(db, user, command = "") {
  const scoring = backendDecisionScoringModel(db, user, command);
  const feeds = backendLiveKnowledgeFeedReadiness(db);
  const profile = db.profile || {};
  const predictions = [];
  const add = (module, priority, message, commandText) => predictions.push({ module, priority, message, command: commandText });
  if ((profile.healthIntakes || []).length && !(profile.telehealthFollowUps || []).length) add("Health", "high", "Health intake exists but follow-up is not scheduled.", "schedule telehealth follow up");
  if ((profile.orders || []).length && !(profile.tradeMessageThreads || []).length) add("Trade", "high", "A trade order needs buyer-seller communication evidence.", "contact buyer");
  if ((profile.orders || []).length && !(profile.mapInsights || []).length) add("Map", "medium", "A sale route exists without route-risk intelligence.", "track my sale route");
  if ((profile.enrollments || []).length && !(profile.certificates || []).length) add("Learning", "medium", "A learner has course progress but no certificate evidence yet.", "issue my certificate");
  if ((profile.applications || []).length && !(profile.interviews || 0)) add("Workforce", "medium", "A job application exists but interview support is not scheduled.", "prepare interview");
  if ((profile.droneScans || []).length && !(profile.fieldInterventions || []).length) add("Drone", "medium", "Drone evidence exists but no field task has been created.", "create field task");
  if (feeds.ready < feeds.total) add("Live feeds", "setup", `${feeds.ready}/${feeds.total} live knowledge feeds are ready.`, "explain live intelligence feeds");
  if (!predictions.length) add("Nexus", "ready", "No immediate gap detected. Keep guiding the active request.", scoring.command);
  return { scoring, feeds, predictions: predictions.slice(0, 6), nextBestAction: predictions[0]?.command || scoring.command };
}

function conversationModuleSignal(text) {
  const lower = String(text || "").toLowerCase();
  if (/\b(wrong|not|instead|mean|meant)\b.*\b(crop|farm|farmer|maize|cassava|field|harvest|buyer|sell)\b/.test(lower)
    || /\b(crop|farm|farmer|maize|cassava|field|harvest|buyer|sell)\b.*\b(not doctor|not health|not clinic|not job)\b/.test(lower)) {
    return { module: "AgriTrade", section: "trade", score: 4 };
  }
  if (/\b(wrong|not|instead|mean|meant)\b.*\b(medicine|clinic|doctor|health|sick|child|patient|pharmacy)\b/.test(lower)
    || /\b(medicine|clinic|doctor|health|sick|child|patient|pharmacy)\b.*\b(not job|not crop|not work)\b/.test(lower)) {
    return { module: "Healthcare", section: "health", score: 4 };
  }
  const signals = [
    { module: "Women & Family", section: "dashboard", keys: ["women", "woman", "mother", "mothers", "family farm", "family agriculture", "women farmer", "women farmers", "children on the farm", "youth learning", "girls in agriculture", "cooperative"] },
    { module: "Healthcare", section: "health", keys: ["telehealth", "health", "patient", "care", "doctor", "provider", "clinician", "nurse", "clinic", "mobile clinic", "register", "registration", "mother", "mama", "mi mama", "body pain", "pain", "sick", "what now", "cold", "flu", "cough", "fever", "symptom", "medicine", "pharmacy", "remedio", "dawa", "magani", "oogun", "kliniki", "daktari", "likita", "outbreak", "ebola", "vitals", "referral", "hearing", "visual", "blind", "deaf"] },
    { module: "Learning", section: "learning", keys: ["learning", "training", "course", "lesson", "quiz", "certificate", "learner", "student", "graduate", "graduated", "university", "degree", "captions", "audio guide"] },
    { module: "Workforce", section: "workforce", keys: ["workforce", "work", "job", "jobs", "career", "role", "worker", "candidate", "biochemistry", "biology", "chemistry", "laboratory", "interview", "shift", "mentor", "apply", "hiring", "position", "money", "income"] },
    { module: "AgriTrade", section: "trade", keys: ["agritrade", "trade", "farmer", "crop", "buyer", "sell", "market", "order", "wallet", "payment", "logistics", "drone", "field", "farm", "no rain", "crop dying", "crop bad", "plant sick", "maize bad", "cassava bad", "pest", "disease", "drought", "irrigation", "field moisture", "yellow leaves", "bugs eating"] },
    { module: "Maps", section: "map", keys: ["map", "route", "location", "gps", "geospatial", "corridor", "country", "risk", "driver lost", "lost driver", "no gps", "where to go", "road safe", "road unsafe", "clinic near", "pharmacy near"] },
    { module: "Integrations", section: "integrations", keys: ["integration", "provider", "engine", "api", "service", "credential", "render", "openai", "twilio"] },
    { module: "Agent AI", section: "agent", keys: ["agent", "agrinexus", "nexus", "assistant", "voice", "conversation", "autopilot", "mission", "reason"] }
  ];
  const scored = signals
    .map(signal => ({ ...signal, score: signal.keys.reduce((total, key) => total + (lower.includes(key) ? 1 : 0), 0) }))
    .sort((a, b) => b.score - a.score);
  return scored[0]?.score ? scored[0] : { module: "Platform", section: "dashboard", score: 0 };
}

function isOpenEndedConversation(lower) {
  const value = String(lower || "").trim();
  if (!value) return false;
  return /^(what|how|why|when|where|who|can|could|would|should|tell|explain|describe|summarize)\b/.test(value)
    || /\b(question|wondering|understand|explain|tell me|what about|how about|can it|can you|could it|does it|will it)\b/.test(value);
}

function isClearWorkflowExecution(lower) {
  const value = String(lower || "").trim();
  if (!value) return false;
  return /^(open|start|run|show|change|switch|translate|track|apply|complete|issue|create|call|message|contact|schedule|submit|send)\b/.test(value)
    && /\b(map|course|lesson|certificate|language|route|shipment|job|role|doctor|provider|clinic|buyer|seller|crop|order|payment|wallet|intake|caption|audio|drone|health check|live service|mission|autopilot)\b/.test(value);
}

function isOpenDialogConversation(command = "", options = {}) {
  const value = String(command || "").toLowerCase().replace(/\s+/g, " ").trim();
  if (!value) return false;
  if (isClearWorkflowExecution(value)) return false;
  if (/^(yes|yeah|yep|confirm|do it|run it)\b/.test(value)) return false;
  if (/^(no|nope)\s*$/.test(value)) return false;
  if (/^(cancel|stop|pause|quiet)\b/.test(value)) return false;
  if (/\b(change|switch|set|use)\s+(language|voice|mode)\b/.test(value)) return false;
  const cropDistress = /\b(no rain|crop dying|crop bad|plant sick|maize bad|cassava bad|pest|disease|harvest failing|farm problem)\b/.test(value);
  if (utilityAssistantKind(command, value) && !cropDistress) return false;
  if (isOpenEndedConversation(value)) return true;
  const tokens = value.split(/\s+/).filter(Boolean);
  const lifeProblem = /\b(i|im|i'm|we|my|our|someone|patient|farmer|student|worker|learner|mother|child|family)\b.*\b(need|want|have|has|looking|trying|register|registration|graduated|studied|sick|hurt|pain|medicine|doctor|clinic|mobile clinic|job|work|apply|learn|course|sell|buy|crop|farm|route|buyer|provider|confused|understand|help)\b/.test(value);
  const ruralContext = /\b(farmer|crop|maize|cassava|rice|clinic|pharmacy|doctor|provider|course|job|market|buyer|seller|kenya|south africa|nigeria|ghana|rwanda|tanzania|egypt|drc|congo|africa|village|rural)\b/.test(value);
  const conversationalAsk = /\b(help me|walk me|guide me|talk to me|what do i do|what should i do|i don't know|i dont know|can you help|please help)\b/.test(value);
  const shortRuralProblem = /\b(crop bad|crop dying|no rain|farm bad|plant sick|maize bad|cassava bad|child sick|baby sick|mother sick|body pain|pain sick|sick what now|mobile clinic|register my mother|need medicine|no doctor|no clinic|need job|find work|want learn|no understand|dont understand|don't understand|market price|buyer where|route safe)\b/.test(value);
  return shortRuralProblem || (tokens.length >= 6 && (lifeProblem || conversationalAsk || (options.inputMode === "voice" && ruralContext && !isActionRequest(value))));
}

function isRuralDistressConversation(command = "") {
  const value = String(command || "").toLowerCase().replace(/\s+/g, " ").trim();
  if (!value) return false;
  const cropDistress = /\b(no rain|crop dying|crop bad|plant sick|maize bad|cassava bad|pest|disease|harvest failing|farm problem|yellow leaves|bugs eating|farm dry|field dry|crop dry|crop stress|crops going bad)\b/.test(value)
    && /\b(crop|crops|farm|farmer|field|maize|cassava|plant|plants|harvest|soil|rain|water|irrigat)\b/.test(value);
  const careDistress = /\b(cannot breathe|can't breathe|no doctor|no clinic|baby sick|child sick|mother sick|grandma sick|mama sick|mi mama sick|people here sick|village.*sick|sick.*village|sick.*no words|no words.*sick|ayuda.*clinic|ayuda.*sick|preciso remedio|medicine for child|medicine.*child|child.*medicine|bleeding|very hot|weak|need medicine|body pain|pain sick)\b/.test(value);
  const lowLiteracyNeed = /\b(no understand|don't understand|dont understand|cannot read|can't read|too many words|bad internet|no computer|i am confused|i'm confused)\b/.test(value);
  const workDistress = /\b(need work|find work|no job|need job|apply job|no certificate|finished school|graduated university)\b/.test(value);
  const mapDistress = /\b(driver lost|lost driver|no gps|where to go|road unsafe|road safe|route safe|map near|clinic near|pharmacy near)\b/.test(value);
  const correctionDistress = /\b(wrong|heard me wrong|you heard|not doctor|not job|not health|not crop|i mean|mean)\b/.test(value)
    && /\b(crop|farm|medicine|clinic|doctor|health|job|work|map|route|course|lesson)\b/.test(value);
  return cropDistress || careDistress || lowLiteracyNeed || workDistress || mapDistress || correctionDistress;
}

function isActionRequest(lower) {
  return /\b(open|start|run|create|build|make|send|submit|apply|schedule|connect|contact|call|message|advance|complete|issue|record|capture|test|deploy|change|switch|translate|track|prepare)\b/.test(String(lower || ""));
}

function ruralCommunicationSupportModel(command = "", moduleSignal = null, user = {}) {
  const value = String(command || "").toLowerCase();
  const moduleName = moduleSignal?.module || conversationModuleSignal(command).module;
  const name = String(user?.name || "").split(/\s+/)[0] || "there";
  const resilience = conversationResilienceModel(command, user, {});
  const stakeholderAudience = stakeholderAudienceConversationModel(command, user, {});
  const africaStyle = ruralAfricaConversationModel(command, user);
  const kenyaStyle = ruralKenyaCommunicationModel(command, user);
  const models = {
    Healthcare: {
      audience: "patient, caregiver, elder, or mobile clinic user",
      likelyNeed: /\b(medicine|pharmacy|drug|remedy|pills)\b/.test(value) ? "medicine or pharmacy access" : "care access",
      plainGoal: "Help the person understand the safe next care step without diagnosing.",
      nextQuestion: "Where are you, and is this an emergency right now?",
      safetyRule: "Do not diagnose. Ask about danger signs and guide to urgent help when needed."
    },
    Learning: {
      audience: "student, learner, parent, or low-literacy user",
      likelyNeed: "a lesson explained in simple words",
      plainGoal: "Help the learner choose one skill and complete one small step.",
      nextQuestion: "What do you want to learn today?",
      safetyRule: "Keep instructions short and offer audio, captions, or slower speech."
    },
    Workforce: {
      audience: "job seeker, graduate, worker, or family supporter",
      likelyNeed: /\b(graduated|degree|university|biochemistry|biology|chemistry)\b/.test(value) ? "career guidance after school" : "job access",
      plainGoal: "Help the person understand realistic roles and prepare one application step.",
      nextQuestion: "What country do you want to work in, and what skill or school background do you have?",
      safetyRule: "Do not promise a job. Explain options and prepare the next application step."
    },
    AgriTrade: {
      audience: "farmer, seller, buyer, cooperative, or family farm",
      likelyNeed: /\b(bad|sick|disease|pest|dry|yellow|dying)\b/.test(value) ? "crop problem guidance" : "market, buyer, or delivery help",
      plainGoal: "Help the farmer protect the crop, understand market choices, and move one step toward selling or delivery.",
      nextQuestion: "What crop is it, and what village or area is the farm in?",
      safetyRule: "Do not guess crop disease as fact. Ask for photo, location, crop, and urgency."
    },
    Maps: {
      audience: "traveler, driver, health worker, farmer, or logistics user",
      likelyNeed: "location, route, or nearby service guidance",
      plainGoal: "Help the person see where to go and what route or place matters.",
      nextQuestion: "What place are you starting from, and where do you need to go?",
      safetyRule: "Use map/provider data when available and explain uncertainty clearly."
    },
    Platform: {
      audience: "non-technical user",
      likelyNeed: "general guidance",
      plainGoal: "Understand the person's goal and guide one step at a time.",
      nextQuestion: "Tell me what you need: health, crops, work, learning, map, or market.",
      safetyRule: "Avoid technical language and ask only one question."
    }
  };
  const selected = models[moduleName] || models.Platform;
  return {
    userName: name,
    module: moduleName,
    ...selected,
    resilience,
    stakeholderAudience,
    africaStyle,
    kenyaStyle,
    styleRules: [
      "Use short sentences.",
      "Use everyday words.",
      "Ask one question at a time.",
      "Repeat the user's goal in simple language.",
      resilience.active ? `Use conversation resilience: ${resilience.responseContract.join(" ")}` : null,
      `Shape the answer for ${stakeholderAudience.key}: ${stakeholderAudience.responseShape}.`,
      "If unsure, ask a gentle clarification instead of forcing a menu.",
      "Offer voice, captions, slower speech, and local language support.",
      africaStyle.active ? "For rural Africa, accept incomplete sentences, fragments, mixed language, and repeated attempts without shame." : null,
      africaStyle.active && moduleName === "Healthcare" ? "For medical speech, do not diagnose; ask danger signs and location first, then route to human care, clinic, mobile clinic, pharmacy, or emergency help." : null,
      kenyaStyle.active ? "For rural Kenya, use respectful Kiswahili/plain Kenyan English support: short sentences, one question, clear meaning, no caricature." : null
    ].filter(Boolean),
    ruralAfricaPhrases: africaStyle.active ? africaStyle.examples : [],
    localPhrases: kenyaStyle.active ? kenyaStyle.phrases : [],
    examples: kenyaStyle.active ? [
      "Pole. Nimekusikia. Sorry, I hear you.",
      "Twende hatua moja. Let us go one step.",
      "Unahitaji nini kwanza? What do you need first?"
    ] : [
      "I understand. Let us take this one step at a time.",
      "Tell me where you are, then I can guide the next step.",
      "I may have heard that wrong. Say it again slowly, or say health, crops, work, learning, or map."
    ],
    localCommunicationStyle: kenyaStyle.active ? kenyaStyle.style : africaStyle.style
  };
}

function ruralAfricaConversationModel(command = "", user = {}) {
  const value = String(command || "").toLowerCase().replace(/\s+/g, " ").trim();
  const words = value.split(/\s+/).filter(Boolean);
  const userLanguage = String(user?.language || "").toLowerCase();
  const incompleteSentence = words.length <= 7
    || /\b(no|need|want|help|sick|pain|hot|bleed|medicine|doctor|clinic|crop|bad|rain|job|work|learn|map|lost)\b/.test(value)
    || !/[.?!]$/.test(String(command || "").trim());
  const ruralSignal = /\b(africa|rural|village|farm|farmer|grandma|elder|mother|mama|child|baby|doctor|clinic|medicine|pharmacy|crop|market|buyer|job|course|map|road|route|nigeria|ghana|kenya|tanzania|rwanda|uganda|ethiopia|egypt|drc|congo|senegal|mali|zambia|south africa|hausa|yoruba|igbo|swahili|kiswahili|amharic|oromo|lingala|french|arabic|portuguese|pidgin)\b/.test(value);
  const mixedLanguageSignal = /\b(ayuda|aide|preciso|remedio|dawa|magani|oogun|kliniki|likita|daktari|kazi|shamba|soko|mazao|tafadhali|abeg|wahala|dey|sabi)\b/.test(value)
    || ["sw", "fr", "ar", "pt", "ha", "yo", "ig", "am"].includes(userLanguage);
  const healthFragment = /\b(baby|child|mama|mother|grandma|elder|person|patient)?\s*(hot|fever|sick|pain|bleed|bleeding|weak|dizzy|breath|breathe|medicine|doctor|clinic|pharmacy|injury|wound|rash|vomit|diarrhea)\b/.test(value)
    || /\b(no doctor|no clinic|need medicine|medicine finished|body pain|child sick|baby hot|mama sick)\b/.test(value);
  const active = ruralSignal || mixedLanguageSignal || (incompleteSentence && healthFragment);
  return {
    active,
    style: active ? "pan-african-rural-plain-language" : "standard",
    policy: "Accept incomplete rural African speech, mixed language, and fragments; never shame grammar; never invent medical certainty.",
    responseShape: active ? "reflect the likely need, ask one safety or location question, then guide the next practical step" : "standard plain-language",
    medicalSafety: {
      boundary: "Nexus is not a doctor and does not diagnose.",
      dangerSigns: ["trouble breathing", "heavy bleeding", "unconscious", "chest pain", "severe weakness", "baby or elder very sick", "fast worsening symptoms"],
      firstQuestion: healthFragment ? "Is the person breathing, awake, and safe right now? Where are they?" : "Where are you, and what help do you need first?",
      nextSteps: ["emergency help", "nearest clinic", "mobile clinic", "pharmacy support", "provider callback", "paper-to-digital handoff"]
    },
    examples: [
      "Baby hot... no doctor.",
      "Medicine finished... village far.",
      "Crop bad... rain no come.",
      "Job please... no certificate.",
      "Map clinic... near me."
    ],
    intentOpeners: {
      Healthcare: healthFragment ? "I hear health danger. Is the person breathing, awake, and safe right now? Where are they?" : "I hear health help. Where are you, and do you need clinic, medicine, or phone help?",
      Learning: "I hear learning help. What do you want to learn first?",
      Workforce: "I hear work help. What country are you in, and what work can you do?",
      AgriTrade: "I hear farm or market help. What crop is it, and where is the farm?",
      Maps: "I hear map help. Where are you starting, and where do you need to go?",
      Platform: "I may have heard only part of that. Say one word: health, crop, work, learning, map, or medicine."
    }
  };
}

function ruralKenyaCommunicationModel(command = "", user = {}) {
  const value = String(command || "").toLowerCase().replace(/\s+/g, " ").trim();
  const userLanguage = String(user?.language || "").toLowerCase();
  const active = userLanguage === "sw"
    || /\b(kenya|kenyan|kiswahili|swahili|shamba|mazao|soko|dawa|kliniki|daktari|mama|nyanya|bibi|mtoto|tafadhali|pole|habari|niko|nataka|nahitaji|nisaidie|msaada|bei|mahindi|ngombe|maziwa|matatu|m-pesa|mpesa)\b/.test(value)
    || /\b(rural farmer|village farmer|grandma|elder|plain village|speak simple|talk simple|farmer language)\b/.test(value);
  return {
    active,
    style: active ? "rural-kenya-plain-kiswahili" : "standard",
    policy: "Respectful rural Kenya support means Kiswahili/plain Kenyan English, not a fake accent or tribal caricature.",
    responseShape: active ? "greet gently, reflect need, ask one practical question, explain any Kiswahili word in plain meaning" : "standard plain-language",
    phrases: [
      "Pole. Nimekusikia. Sorry, I hear you.",
      "Twende hatua moja. Let us go one step.",
      "Unahitaji nini kwanza? What do you need first?",
      "Ni shamba, afya, kazi, masomo, au ramani? Is it farm, health, work, learning, or map?",
      "Nitasema kwa maneno rahisi. I will use simple words."
    ],
    intentOpeners: {
      Healthcare: "Pole. Afya kwanza. Where are you, and do you need clinic, medicine, or phone help?",
      Learning: "Sawa. We will learn slowly. What lesson do you want first?",
      Workforce: "Sawa. Let us look for work. What country and what work can you do?",
      AgriTrade: "Sawa. Tuanze na shamba. What crop is it, and do you want to sell, move, or check a problem?",
      Maps: "Sawa. Tell me the start place and the place you need to reach.",
      Platform: "Twende hatua moja. Tell me first: health, crops, work, learning, map, or medicine."
    }
  };
}

function frontierCommunicationIntelligenceModel(command = "", moduleSignal = null, user = {}, options = {}) {
  const value = String(command || "").toLowerCase().replace(/\s+/g, " ").trim();
  const words = value.split(/\s+/).filter(Boolean);
  const ruralSupport = ruralCommunicationSupportModel(command, moduleSignal, user);
  const resilience = ruralSupport.resilience || conversationResilienceModel(command, user, {});
  const stakeholderAudience = ruralSupport.stakeholderAudience || stakeholderAudienceConversationModel(command, user, {});
  const africaStyle = ruralSupport.africaStyle || ruralAfricaConversationModel(command, user);
  const kenyaStyle = ruralSupport.kenyaStyle || ruralKenyaCommunicationModel(command, user);
  const urgencySignals = [
    /\b(emergency|urgent|danger|bleeding|cannot breathe|trouble breathing|chest pain|unconscious|seizure|poison|baby sick|child sick|very hot|dehydrated)\b/.test(value),
    /\b(crop dying|crop bad|plant sick|pest|disease|all crop|harvest failing|buyer waiting|shipment stuck)\b/.test(value),
    /\b(no money|no food|no medicine|no clinic|no doctor|stranded|lost|unsafe route)\b/.test(value)
  ].filter(Boolean).length;
  const uncertaintySignals = [
    /\b(maybe|not sure|dont know|don't know|i no understand|no understand|confused|what do i do|help me|can you help|i think|maybe)\b/.test(value),
    words.length <= 5,
    /\b(thing|stuff|problem|bad|sick|help)\b/.test(value) && !/\b(where|what|who|when|how)\b/.test(value)
  ].filter(Boolean).length;
  const accessSignals = [
    /\b(blind|cant see|can't see|visual|deaf|cant hear|can't hear|hearing|read aloud|caption|slow|speak slowly|grandma|elder|old|low tech|no phone|shared phone)\b/.test(value),
    /\b(no internet|bad internet|low signal|offline|battery|small phone|rural)\b/.test(value)
  ].filter(Boolean).length;
  const languageSignals = [
    /\b(translate|language|french|swahili|kiswahili|arabic|spanish|portuguese|english|hausa|yoruba|igbo|amharic|oromo|kinyarwanda|lingala)\b/.test(value),
    Boolean(options.targetLanguage && options.targetLanguage !== "en")
  ].filter(Boolean).length;
  const locationNeeded = /\b(near me|nearest|closest|where|clinic|pharmacy|route|map|market|buyer|seller|job|kenya|south africa|nigeria|ghana|rwanda|tanzania|egypt|drc|congo|village|farm)\b/.test(value);
  const outcomeNeeded = /\b(apply|sell|buy|call|contact|find|choose|decide|learn|start|track|deliver|medicine|doctor|clinic|course|job)\b/.test(value);
  const confidence = Math.max(0.36, Math.min(0.96,
    0.52
    + (moduleSignal?.score ? Math.min(0.18, moduleSignal.score * 0.06) : 0)
    + (outcomeNeeded ? 0.1 : 0)
    + (locationNeeded ? 0.06 : 0)
    - (uncertaintySignals * 0.08)
  ));
  const urgency = urgencySignals >= 2 ? "high" : urgencySignals === 1 ? "medium" : "normal";
  const communicationMode = accessSignals ? "accessibility-first" : languageSignals ? "multilingual-plain-language" : uncertaintySignals ? "clarify-before-action" : "plain-action-guide";
  const answerShape = urgency === "high"
    ? "safety-first"
    : confidence < 0.58
      ? "one-question-clarifier"
      : outcomeNeeded
        ? "answer-then-next-step"
        : "short-teachback";
  const nextQuestions = {
    Healthcare: urgency === "high" ? "Is the person safe right now, and where are they?" : "Where are you, and do you want clinic, medicine, or phone/video health help?",
    Learning: "What do you want to learn today, and should I explain it slowly or with captions?",
    Workforce: "What country do you want to work in, and what work or school experience do you have?",
    AgriTrade: "What crop is it, where is the farm, and are you trying to save it, sell it, or move it?",
    Maps: "Where are you starting from, and where do you need to go?",
    Platform: "Tell me the area: health, crops, work, learning, map, or market."
  };
  const nextQuestion = nextQuestions[ruralSupport.module] || nextQuestions.Platform;
  const safeguards = [
    ruralSupport.module === "Healthcare" ? "No diagnosis; guide access, danger signs, consent, clinic, pharmacy, or emergency help." : null,
    ruralSupport.module === "Workforce" ? "No job promise; explain pathways and prepare application evidence." : null,
    ruralSupport.module === "AgriTrade" ? "No crop disease certainty without photo/data; ask for crop, location, symptoms, buyer or route context." : null,
    "If confidence is low, ask one question before action.",
    "Keep the response short enough for voice."
  ].filter(Boolean);
  return {
    version: "frontier-rural-communication-v1",
    module: ruralSupport.module,
    audience: ruralSupport.audience,
    stakeholderAudience,
    resilience,
    likelyNeed: ruralSupport.likelyNeed,
    confidence: Number(confidence.toFixed(2)),
    urgency,
    communicationMode,
    answerShape,
    nextQuestion,
    locationNeeded,
    outcomeNeeded,
    languageSupport: languageSignals ? "translate-or-adapt-language" : "use-current-language",
    accessibilitySupport: accessSignals ? "offer-audio-captions-slower-speech" : "standard",
    localCommunicationStyle: kenyaStyle.active ? kenyaStyle.style : africaStyle.style,
    ruralAfricaPhrases: africaStyle.active ? africaStyle.examples : [],
    medicalSafety: africaStyle.active ? africaStyle.medicalSafety : null,
    localPhrases: kenyaStyle.active ? kenyaStyle.phrases : [],
    teachBack: `I hear that you may need ${ruralSupport.likelyNeed}.`,
    rules: [
      "Start by reflecting the user's need in simple words.",
      resilience.active ? "Use teach-back before action because the user may not have formal words." : null,
      `Use stakeholder behavior for ${stakeholderAudience.key}: ${stakeholderAudience.tone}.`,
      "Use at most three short sentences before asking for the next detail.",
      "Ask one question at a time.",
      "Prefer local examples: farm, clinic, medicine, job, market, route, lesson.",
      "Do not punish imperfect grammar or mixed language.",
      africaStyle.active ? "Accept incomplete rural African speech and ask one clarifying question instead of forcing a menu." : null,
      africaStyle.active && ruralSupport.module === "Healthcare" ? "Medical users may speak in fragments; ask danger signs and location before any other detail." : null,
      "If the user sounds stuck, guide instead of listing menus.",
      "If there is risk, explain danger signs and route to human help.",
      kenyaStyle.active ? "For rural Kenya, use light Kiswahili/plain English, one question, clear meaning, and no fake dialect." : null
    ].filter(Boolean),
    safeguards
  };
}

function updateConversationUserModel(profile, command) {
  ensureAiProfile(profile);
  const text = String(command || "").trim();
  const lower = text.toLowerCase();
  const model = profile.agentMemory.userModel || {};
  const nameMatch = text.match(/\b(?:my name is|i am|i'm|this is)\s+([A-Z][a-zA-Z'-]{1,30})\b/);
  if (nameMatch) model.name = nameMatch[1];
  if (/\bfarmer|crop|field|buyer|sell|farm\b/.test(lower)) model.currentPersona = "farmer-or-trade-operator";
  if (/\b(government|ministry|minister|county|district|public sector|policy|procurement|official|regulator)\b/.test(lower)) model.currentAudience = "government";
  if (/\b(ngo|nonprofit|non-profit|field partner|implementing partner|donor|foundation|aid|relief|community organization|cbo)\b/.test(lower)) model.currentAudience = "ngo";
  if (/\bwomen|woman|mother|mothers|family farm|family agriculture|women farmer|women farmers|children on the farm|youth learning|girls in agriculture|cooperative\b/.test(lower)) model.currentPersona = "women-family-rural-support";
  if (/\bpatient|care|telehealth|doctor|health\b/.test(lower)) model.currentPersona = "health-access-user";
  if (/\blearner|student|training|course|lesson\b/.test(lower)) model.currentPersona = "learner";
  if (/\bjob|workforce|worker|candidate|interview\b/.test(lower)) model.currentPersona = "workforce-candidate";
  if (/\binvestor|funding|presentation\b/.test(lower)) model.currentAudience = "investor-government";
  if (/\bvoice|speak|talk|listen|microphone|agrinexus|nexus\b/.test(lower)) model.preferredInteraction = "voice-first";
  if (/\bnon technical|non-technical|simple|easy|plain language|low tech|low-tech\b/.test(lower)) model.communicationStyle = "plain-language-step-by-step";
  if (/\b(no school|not educated|cannot read|can't read|cant read|cannot write|can't write|cant write|no english|small english|broken english|dont know words|don't know words|explain simple|read for me)\b/.test(lower)) model.communicationStyle = "conversation-resilience-v1";
  if (/\b(rural africa|african farmer|grandma|elder|incomplete sentence|broken english|mixed language|pidgin|speak simple|talk simple|village)\b/.test(lower)) model.communicationStyle = "pan-african-rural-plain-language";
  if (/\b(kenya|kenyan|kiswahili|swahili|shamba|soko|dawa|kliniki|rural farmer|village farmer|grandma|elder|farmer language|plain village)\b/.test(lower)) model.communicationStyle = "rural-kenya-plain-kiswahili";
  if (/\bread aloud|audio|voice guide|blind|visual|visually impaired|large print|screen reader\b/.test(lower)) model.accessibilityMode = "visual-or-audio-support";
  if (/\bdeaf|hearing impaired|hard of hearing|caption|captions|transcript|sign language\b/.test(lower)) model.accessibilityMode = "hearing-support";
  if (/\blow bandwidth|offline|poor internet|bad internet|no internet|rural signal\b/.test(lower)) model.connectivityMode = "low-bandwidth";
  if (/\bspanish|espanol|español\b/.test(lower)) model.lastRequestedLanguage = "es";
  if (/\bfrench|francais|français\b/.test(lower)) model.lastRequestedLanguage = "fr";
  if (/\bkiswahili|swahili\b/.test(lower)) model.lastRequestedLanguage = "sw";
  if (/\barabic|arabic-speaking|عربي\b/.test(lower)) model.lastRequestedLanguage = "ar";
  model.lastAdaptiveSignals = {
    persona: model.currentPersona || "general-operator",
    audience: model.currentAudience || "community-user",
    style: model.communicationStyle || "plain-language-step-by-step",
    accessibility: model.accessibilityMode || "standard",
    connectivity: model.connectivityMode || "standard"
  };
  model.lastSeenAt = new Date().toISOString();
  profile.agentMemory.userModel = model;
  if (nameMatch) rememberAgentMemory(profile, `User name is ${model.name}.`, { source: "conversation-user-model", category: "fact", module: "Profile", confidence: 0.94 });
  if (model.preferredInteraction) rememberAgentMemory(profile, `User prefers ${model.preferredInteraction} interaction.`, { source: "conversation-user-model", category: "preference", module: "Agent AI", confidence: 0.86 });
  if (model.communicationStyle) rememberAgentMemory(profile, `User needs ${model.communicationStyle} communication.`, { source: "conversation-user-model", category: "preference", module: "Agent AI", confidence: 0.86 });
  if (model.accessibilityMode && model.accessibilityMode !== "standard") rememberAgentMemory(profile, `User needs ${model.accessibilityMode}.`, { source: "conversation-user-model", category: "preference", module: "Healthcare", confidence: 0.9 });
  if (model.connectivityMode && model.connectivityMode !== "standard") rememberAgentMemory(profile, `User may need ${model.connectivityMode} support.`, { source: "conversation-user-model", category: "preference", module: "Integrations", confidence: 0.84 });
  if (model.lastRequestedLanguage) rememberAgentMemory(profile, `User recently requested language ${model.lastRequestedLanguage}.`, { source: "conversation-user-model", category: "preference", module: "Profile", confidence: 0.82 });
  return model;
}

function localConversationalAnswer(db, user, command, moduleSignal, memories, options = {}) {
  const { country, route } = activeContext(db);
  const modeContext = options.modeContext || {};
  const platformMode = options.mode || modeContext.mode || "user";
  const ruralSupport = ruralCommunicationSupportModel(command, moduleSignal, user);
  const frontierCommunication = frontierCommunicationIntelligenceModel(command, moduleSignal, user, options);
  const resilience = ruralSupport.resilience || conversationResilienceModel(command, user, db.profile.agentMemory.userModel || {});
  const stakeholderAudience = ruralSupport.stakeholderAudience || stakeholderAudienceConversationModel(command, user, db.profile.agentMemory.userModel || {});
  const africaStyle = ruralSupport.africaStyle || ruralAfricaConversationModel(command, user);
  const kenyaStyle = ruralSupport.kenyaStyle || ruralKenyaCommunicationModel(command, user);
  const memoryPreview = memories
    .slice(0, 2)
    .map(item => String(item.text || item.response || item.command || "").replace(/\s+/g, " ").trim())
    .filter(Boolean)
    .map(text => text.length > 120 ? `${text.slice(0, 117)}...` : text);
  const memoryLine = memories.length
    ? `I am using ${memoryPreview.length} relevant memory cue(s): ${memoryPreview.join(" | ")}.`
    : "I do not need extra setup to guide this locally.";
  const moduleAnswers = {
    Healthcare: `Telehealth can guide a user from intake to accessible support, representative connection, consent, vitals, referral, care plan, follow-up, and public-health risk review. For sensitive care actions, I should explain the step and ask before creating records.`,
    Learning: `Learning can guide a learner through course selection, lesson progress, captions, audio guides, offline packets, quizzes, and certificates. The strongest experience is conversational: I ask the learner's goal, language, and access needs, then move one step at a time.`,
    Workforce: `Workforce can help someone build a profile, review readiness gaps, match roles, apply, schedule interviews, assign mentors, verify documents, plan shifts, and prepare payroll or performance evidence.`,
    AgriTrade: `AgriTrade can help a farmer or seller review crop readiness, run drone field intelligence, prepare buyer communication, create orders, assess route risk, check quality and cold-chain needs, and prepare payment evidence.`,
    "Women & Family": `Women and family agriculture support can guide women farmers, mothers, caregivers, youth learners, and cooperatives through safe learning, family health navigation, crop-to-market selling, accessibility support, and evidence for partners without replacing clinicians or exposing children to labor.`,
    Maps: `Maps can connect country context, route checkpoints, facility access, route risk, public-health or trade evidence, and live location tracking when the browser allows GPS.`,
    Integrations: `Integrations can test live engines, provider status, OpenAI, voice, translation, maps, jobs, courses, telehealth, trade, drones, communications, billing, and auth readiness.`,
    "Agent AI": `The agent layer can listen, remember context, answer questions, stage safe actions, ask for confirmation, run approved workflows, summarize what happened, and recommend the next best step.`
  };
  const base = moduleAnswers[moduleSignal.module] || `AgriNexus connects learning, workforce, telehealth, AgriTrade, drones, maps, AI, integrations, and admin readiness into one guided operating system.`;
  const next = smartNextActions(db, user).items.find(item => item.section === moduleSignal.section) || smartNextActions(db, user).items[0];
  const modeLine = platformMode === "admin"
    ? "Admin conversation: I will focus on readiness, users, risk, evidence, providers, and production operations."
    : platformMode === "investor"
      ? "Investor conversation: I will focus on impact, proof, readiness, rural value, and a clear presentation story."
      : "User conversation: I will keep this simple, voice-first, and one step at a time.";
  db.profile.agentMemory.lastRecommendedAction = next || null;
  if (stakeholderAudience.key === "government") {
    return [
      "For government, the value is public-service delivery with evidence.",
      `Focus: ${stakeholderAudience.wants.slice(0, 4).join(", ")}.`,
      moduleSignal.module === "Healthcare" ? "Health guidance stays non-diagnostic and routes people to human care." : base,
      stakeholderAudience.nextQuestion
    ].join(" ");
  }
  if (stakeholderAudience.key === "ngo") {
    return [
      "For an NGO or field partner, Nexus turns community need into a trackable field workflow.",
      `Focus: ${stakeholderAudience.wants.slice(0, 4).join(", ")}.`,
      moduleSignal.module === "Healthcare" ? "It can collect access needs, prepare handoff packets, and support clinic, pharmacy, or mobile-clinic routing without diagnosing." : base,
      stakeholderAudience.nextQuestion
    ].join(" ");
  }
  if (resilience.active && platformMode === "user") {
    if (resilience.groupSpeechRisk) {
      return [
        resilience.plainOpening,
        "I will not act on side conversation.",
        "Say Nexus with one clear request when you want me."
      ].join(" ");
    }
    const resilienceQuestion = resilience.nextQuestionByModule?.[moduleSignal.module] || resilience.nextQuestion;
    return [
      resilience.plainOpening,
      moduleSignal.module === "Healthcare" ? ruralSupport.safetyRule : ruralSupport.plainGoal,
      resilienceQuestion
    ].join(" ");
  }
  if (platformMode === "user" && (options.openDialog || isOpenDialogConversation(command, options))) {
    if (stakeholderAudience.key === "grandma") {
      return [
        "I hear you.",
        moduleSignal.module === "Healthcare" ? "I am not a doctor, but I can help you find the safest next care step." : ruralSupport.plainGoal,
        stakeholderAudience.nextQuestion
      ].join(" ");
    }
    if (africaStyle.active && !kenyaStyle.active) {
      return [
        africaStyle.intentOpeners[moduleSignal.module] || africaStyle.intentOpeners.Platform,
        moduleSignal.module === "Healthcare" ? africaStyle.medicalSafety.boundary : ruralSupport.plainGoal,
        frontierCommunication.nextQuestion
      ].join(" ");
    }
    if (kenyaStyle.active) {
      return [
        kenyaStyle.intentOpeners[moduleSignal.module] || kenyaStyle.intentOpeners.Platform,
        ruralSupport.safetyRule,
        frontierCommunication.nextQuestion
      ].join(" ");
    }
    return [
      `${frontierCommunication.teachBack}`,
      frontierCommunication.urgency === "high" ? frontierCommunication.safeguards[0] || ruralSupport.safetyRule : ruralSupport.plainGoal,
      frontierCommunication.nextQuestion
    ].join(" ");
  }
  return [
    modeLine,
    base,
    `Current context: ${country.name}, ${route.name}, checkpoint ${db.profile.activeCheckpoint}.`,
    memoryLine,
    next ? `Best next step: ${next.title}. ${next.detail}` : "Best next step: tell me the module and the outcome you want, and I will guide it."
  ].join(" ");
}

async function conversationalReasoningResponse(db, user, command, options = {}) {
  ensureAiProfile(db.profile);
  const lower = String(command || "").toLowerCase();
  const moduleSignal = conversationModuleSignal(command);
  const memories = retrieveAgentMemories(db.profile, command, 5);
  const reasoning = aiReasoningSnapshot(db, user, command, moduleSignal, memories, options);
  const reasoningLanguageProduction = reasoningLanguageProductionEngine(db, user, command, { moduleSignal, memories, reasoning, targetLanguage: options.targetLanguage });
  const openDialog = isOpenDialogConversation(command, options);
  const ruralSupport = ruralCommunicationSupportModel(command, moduleSignal, user);
  const frontierCommunication = frontierCommunicationIntelligenceModel(command, moduleSignal, user, options);
  const resilience = ruralSupport.resilience || conversationResilienceModel(command, user, db.profile.agentMemory.userModel || {});
  const stakeholderAudience = ruralSupport.stakeholderAudience || stakeholderAudienceConversationModel(command, user, db.profile.agentMemory.userModel || {});
  const africaStyle = ruralSupport.africaStyle || ruralAfricaConversationModel(command, user);
  const kenyaStyle = ruralSupport.kenyaStyle || ruralKenyaCommunicationModel(command, user);
  const { country, route } = activeContext(db);
  const modeContext = options.modeContext || {};
  const platformMode = options.mode || modeContext.mode || "user";
  const modeInstructions = {
    user: "You are speaking to an everyday user. Keep it very simple, friendly, and step-by-step. Avoid admin language unless the user asks.",
    admin: "You are speaking to a platform admin. Be operational, direct, and readiness-focused. Mention users, integrations, evidence, risk, health checks, and production gaps when relevant.",
    investor: "You are speaking to an investor or partner reviewer. Be concise, confident, evidence-led, and explain impact, proof, readiness, and the next demo step."
  };
  const profileSummary = {
    readiness: db.profile.readiness,
    activeCourseId: db.profile.activeCourseId,
    applications: (db.profile.applications || []).length,
    healthIntakes: (db.profile.healthIntakes || []).length,
    orders: (db.profile.orders || []).length,
    droneScans: (db.profile.droneScans || []).length,
    lastStatus: db.profile.agentMemory.lastStatus,
    userModel: db.profile.agentMemory.userModel
  };
  let responseText = "";
  let provider = "local-conversation-brain";
  if (process.env.OPENAI_API_KEY) {
    try {
      const response = await fetch("https://api.openai.com/v1/responses", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          model: process.env.OPENAI_AGENT_MODEL || process.env.OPENAI_MODEL || "gpt-4o-mini",
          input: [
            {
              role: "system",
              content: [
                "You are AgriNexus, a warm voice-first operating assistant for rural agriculture, telehealth, learning, workforce, maps, and trade.",
                "Answer the user's question conversationally in plain language.",
                "Use the platform context; do not claim external real-time facts unless they are provided.",
                modeInstructions[platformMode] || modeInstructions.user,
                "You are not limited to a menu. Treat unknown phrases as open dialog: infer the human problem, answer what you can, and ask one useful clarifying question if needed.",
                "For low-digital-literacy users, avoid menus and technical labels. Speak like a trusted guide.",
                `Conversation resilience model: ${resilience.id}; lineage ${resilience.lineage}; profile ${resilience.communicationProfile}; active ${resilience.active}; score ${resilience.score}; band ${resilience.confidenceBand}; mode ${resilience.responseMode}; support moves: ${resilience.supportMoves.join(" ")}; contract: ${resilience.responseContract.join(" ")}; safety rules: ${resilience.safetyRules.join(" ")}`,
                `Stakeholder audience model: ${stakeholderAudience.key}; audience is ${stakeholderAudience.audience}; tone is ${stakeholderAudience.tone}; response shape is ${stakeholderAudience.responseShape}; next question is ${stakeholderAudience.nextQuestion}`,
                `Rural communication model: audience is ${ruralSupport.audience}; likely need is ${ruralSupport.likelyNeed}; plain goal is ${ruralSupport.plainGoal}`,
                `Rural Africa communication style: ${africaStyle.style}. ${africaStyle.policy} ${africaStyle.active ? `Fragment examples: ${africaStyle.examples.join(" | ")}` : ""}`,
                africaStyle.active && moduleSignal.module === "Healthcare" ? `Medical fragment safety: ${africaStyle.medicalSafety.boundary} First ask: ${africaStyle.medicalSafety.firstQuestion}. Danger signs: ${africaStyle.medicalSafety.dangerSigns.join(", ")}.` : "",
                `Rural Kenya communication style: ${kenyaStyle.style}. ${kenyaStyle.policy} ${kenyaStyle.active ? `Useful phrases: ${kenyaStyle.phrases.join(" | ")}` : ""}`,
                `Use this next-question style when useful: ${ruralSupport.nextQuestion}`,
                `Safety boundary: ${ruralSupport.safetyRule}`,
                `Communication rules: ${ruralSupport.styleRules.join(" ")}`,
                `Frontier communication decision: confidence ${frontierCommunication.confidence}, urgency ${frontierCommunication.urgency}, mode ${frontierCommunication.communicationMode}, answer shape ${frontierCommunication.answerShape}.`,
                `Frontier next question: ${frontierCommunication.nextQuestion}`,
                `Frontier rules: ${frontierCommunication.rules.join(" ")}`,
                `Frontier safeguards: ${frontierCommunication.safeguards.join(" ")}`,
                "Carry the conversation across turns. If the user asks a follow-up like tell me more, why, or what next, use the recent conversation context instead of starting over.",
                "If an action may affect records, health, jobs, payment, providers, or messages, recommend confirmation instead of pretending it is already done.",
                "End with one clear next step the user can say, but do not force a yes/no workflow unless the user clearly asked you to execute."
              ].join(" ")
            },
            { role: "user", content: JSON.stringify({ command, moduleSignal, country, route, checkpoint: db.profile.activeCheckpoint, profileSummary, memories, reasoning, ruralSupport, frontierCommunication, conversationResilience: resilience, stakeholderAudience, ruralAfricaCommunication: africaStyle, ruralKenyaCommunication: kenyaStyle, platformMode, modeContext }) }
          ],
          max_output_tokens: 360
        })
      });
      const payload = await response.json().catch(() => ({}));
      if (!response.ok) throw new Error(payload.error?.message || response.statusText);
      responseText = extractResponseText(payload);
      provider = "openai-conversation-brain";
    } catch (error) {
      responseText = localConversationalAnswer(db, user, command, moduleSignal, memories, options);
      provider = "local-after-openai-conversation-error";
      logIntegration(db, {
        providerId: "openai",
        module: "AI",
        action: "agent.conversation_brain_error",
        status: "fallback",
        detail: error.message || "OpenAI conversation brain unavailable.",
        metadata: { command, module: moduleSignal.module }
      });
    }
  } else {
    responseText = localConversationalAnswer(db, user, command, moduleSignal, memories, options);
  }
  db.profile.agentMemory.conversationQuality.openEndedAnswers = Number(db.profile.agentMemory.conversationQuality.openEndedAnswers || 0) + 1;
  db.profile.agentMemory.conversationQuality.lastSignal = moduleSignal.module;
  db.profile.agentMemory.activeModule = moduleSignal.module;
  db.profile.agentMemory.lastRecommendedSection = moduleSignal.section;
  db.profile.agentMemory.lastStatus = "conversation-reasoned";
  db.profile.agentMemory.lastSummary = responseText;
  db.profile.agentMemory.updatedAt = new Date().toISOString();
  logIntegration(db, {
    providerId: "openai",
    module: "AI",
    action: "agent.conversation_brain_answered",
    detail: `Conversation brain answered in ${moduleSignal.module}.`,
    metadata: { provider, command, module: moduleSignal.module, memoriesUsed: memories.map(item => item.id).filter(Boolean), reasoning, reasoningLanguageProduction, ruralSupport, frontierCommunication, conversationResilience: resilience, stakeholderAudience, ruralAfricaCommunication: africaStyle, ruralKenyaCommunication: kenyaStyle },
    dispatch: false
  });
  const shouldStage = options.conversational && !openDialog && isActionRequest(lower) && moduleSignal.section !== "dashboard";
  if (shouldStage) {
    const plan = planAgentToolLocally(command);
    if (plan && plan.tool !== "ai.copilot") {
      const staged = stageAgentAction(db, command, {
        module: plan.module,
        tool: plan.tool,
        action: plan.action,
        section: plan.section,
        planner: "conversation-brain-local",
        confidence: plan.confidence,
        rationale: plan.rationale
      });
      db.profile.agentMemory.conversationQuality.stagedActions = Number(db.profile.agentMemory.conversationQuality.stagedActions || 0) + 1;
      return {
        ...staged,
        response: `${responseText} I can also stage ${plan.action.toLowerCase()} now. Say "yes" to run it, or "no" to cancel.`,
        metadata: { ...staged.metadata, provider, conversationBrain: true, moduleSignal, reasoning, reasoningLanguageProduction, ruralSupport, frontierCommunication, conversationResilience: resilience, stakeholderAudience, ruralAfricaCommunication: africaStyle, ruralKenyaCommunication: kenyaStyle }
      };
    }
  }
  return {
    intent: "conversation.open_reasoning",
    response: responseText,
    status: "completed",
    metadata: { conversationMode: true, openDialog, platformMode, modeContext, redirectSection: moduleSignal.section, provider, moduleSignal, memoriesUsed: memories.map(item => item.id).filter(Boolean), reasoning, reasoningLanguageProduction, ruralSupport, frontierCommunication, conversationResilience: resilience, stakeholderAudience, ruralAfricaCommunication: africaStyle, ruralKenyaCommunication: kenyaStyle }
  };
}

function backendSmartCommandResponse(db, user, command = "", options = {}) {
  const lower = String(command || "").toLowerCase();
  if (/\b(provider activation|activate live providers|finish provider setup|what providers are missing|what keys are missing|what engines are missing|production provider readiness|provider readiness)\b/.test(lower)) {
    const guide = productionActivationGuide(db, runtimeProviders(db));
    const next = guide.nextCriticalGroup;
    const missing = next
      ? [...(next.missing || []), ...(next.missingDirect || [])].filter(Boolean).slice(0, 6).join(", ")
      : "none";
    return {
      intent: "production.provider_activation",
      status: guide.status === "production-ready" ? "completed" : "needs-setup",
      response: guide.status === "production-ready"
        ? `Provider activation is ready: ${guide.readyCount}/${guide.total} engine groups are connected. You can test live services, voice, maps, learning, workforce, telehealth, trade, drones, payments, and communications.`
        : `Provider activation is ${guide.readyCount}/${guide.total}. Next focus: ${next?.title || "provider setup"}. ${next?.nextAction || "Add the missing provider keys in Render and redeploy."} Missing focus: ${missing}.`,
      metadata: { conversationMode: true, redirectSection: "integrations", platformMode: options.mode || options.modeContext?.mode || "user", activationGuide: guide }
    };
  }
  if (/\b(live intelligence feeds|live knowledge feeds|real time feeds|provider feeds|what feeds are live)\b/.test(lower)) {
    const feeds = backendLiveKnowledgeFeedReadiness(db);
    return {
      intent: "conversation.live_feed_readiness",
      status: "completed",
      response: `Live intelligence feed readiness is ${feeds.ready}/${feeds.total}. ${feeds.feeds.map(feed => `${feed.title}: ${feed.ready ? "ready" : "needs provider"} for ${feed.value}`).join(". ")}.`,
      metadata: { conversationMode: true, redirectSection: "integrations", platformMode: options.mode || options.modeContext?.mode || "user", feeds }
    };
  }
  if (/\b(decision score|score your decision|why did you recommend|rank this|score this)\b/.test(lower)) {
    const scoring = backendDecisionScoringModel(db, user, command);
    return {
      intent: "conversation.decision_scoring",
      status: "completed",
      response: `Decision score ${scoring.score}/100. Recommendation: ${scoring.recommendation}. Why: ${scoring.why}. Next command: ${scoring.command}.`,
      metadata: { conversationMode: true, redirectSection: scoring.moduleSignal.section, scoring }
    };
  }
  if (/\b(predict|prediction|predictive|what needs attention|smart recommendation|make a smart recommendation|what should happen next)\b/.test(lower)) {
    const predictive = backendPredictiveAdvisorModel(db, user, command);
    const top = predictive.predictions[0];
    return {
      intent: "conversation.predictive_advisor",
      status: "completed",
      response: `Predictive advisor is active. Intelligence score ${predictive.scoring.score}/100. Top prediction: ${top.module} ${top.priority}: ${top.message} Next best action: ${top.command}. Live feeds ready: ${predictive.feeds.ready}/${predictive.feeds.total}.`,
      metadata: { conversationMode: true, redirectSection: predictive.scoring.moduleSignal.section, predictive }
    };
  }
  return null;
}

function isCurrentKnowledgeQuestion(command = "") {
  const lower = String(command || "").toLowerCase().trim();
  if (!lower) return false;
  if (/\b(weather|temperature|temp|too hot|safe to walk|walk today|rain|raining|forecast)\b/.test(lower)) return false;
  const questionStart = /^(what|what's|whats|how much|how many|where|when|which|compare|tell me|explain|is it|are there|can you find|look up|search)\b/.test(lower);
  const currentSignal = /\b(current|today|now|latest|live|real[-\s]?time|right now|this week|this month|price|cost|rate|market|outbreak|route delay|near me|nearby|available|availability)\b/.test(lower);
  const definitionShape = /^(what is|what's|whats|explain|define|tell me about|describe|teach me)\b/.test(lower) && !currentSignal;
  if (definitionShape) return false;
  const domainSignal = /\b(maize|corn|rice|cassava|yam|beans|crop|crops|commodity|market|buyer|seller|kenya|south africa|nigeria|ghana|rwanda|tanzania|egypt|drc|congo|clinic|pharmacy|hospital|jobs|courses|route|shipment|logistics)\b/.test(lower);
  return (questionStart && (currentSignal || domainSignal)) || (currentSignal && domainSignal);
}

function isConversationalHealthProviderQuestion(command = "") {
  const lower = String(command || "").toLowerCase().trim();
  if (!lower) return false;
  const asksProviderType = /\b(who|what kind|which|best|right|nearest|closest|where)\b.*\b(doctor|provider|clinician|nurse|clinic|hospital)\b/.test(lower);
  const careWords = /\b(cold|flu|fever|cough|sore throat|runny nose|headache|symptom|sick|ill|medicine|medication|pharmacy)\b/.test(lower);
  const providerWords = /\b(doctor|provider|clinician|nurse|clinic|hospital|pharmacy|medicine)\b/.test(lower);
  return (asksProviderType && (careWords || providerWords)) || (careWords && providerWords && /\b(who|what|which|where|can you|help|need)\b/.test(lower));
}

async function healthProviderGuidanceResponse(db, user, command = "", options = {}) {
  const { country } = activeContext(db);
  const memories = retrieveAgentMemories(db.profile, command, 4);
  const safeLocal = [
    "I can help you choose the right kind of care, but I am not a doctor and I cannot diagnose you.",
    "For cold-like symptoms, a primary care clinic, community health nurse, general practitioner, or telehealth provider is usually the right first step.",
    "If there is trouble breathing, chest pain, severe weakness, dehydration, a very high fever, pregnancy, a baby, an older adult, or symptoms getting worse, treat it as urgent and seek emergency care.",
    "Tell me your location and whether you want a clinic, telehealth, or pharmacy support, and I will guide the next step."
  ].join(" ");
  let response = safeLocal;
  let provider = "local-health-provider-advisor";
  if (process.env.OPENAI_API_KEY) {
    try {
      const aiResponse = await fetchWithTimeout("https://api.openai.com/v1/responses", {
        method: "POST",
        headers: {
          authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
          "content-type": "application/json"
        },
        body: JSON.stringify({
          model: process.env.OPENAI_AGENT_MODEL || process.env.OPENAI_MODEL || "gpt-4o-mini",
          input: [
            {
              role: "system",
              content: [
                "You are Nexus, the AgriNexus health access guide for rural users.",
                "Do not diagnose. Do not claim one doctor is best unless a real provider directory is supplied.",
                "Explain the safest type of provider in plain language.",
                "Ask one short follow-up question that moves the user toward clinic, telehealth, pharmacy, or urgent care.",
                "Mention urgent warning signs briefly.",
                "Keep the spoken answer concise and natural."
              ].join(" ")
            },
            { role: "user", content: JSON.stringify({ question: command, country, memories, targetLanguage: options.targetLanguage || user?.language || "en" }) }
          ],
          max_output_tokens: 260
        })
      }, 12000);
      const payload = await aiResponse.json().catch(() => ({}));
      if (!aiResponse.ok) throw new Error(payload.error?.message || aiResponse.statusText);
      response = extractResponseText(payload) || safeLocal;
      provider = "openai-health-provider-advisor";
    } catch (error) {
      logIntegration(db, {
        providerId: "openai",
        module: "Healthcare",
        action: "agent.health_provider_advisor_error",
        status: "fallback",
        detail: error.message || "OpenAI health provider advisor unavailable.",
        metadata: { command },
        dispatch: false
      });
    }
  }
  db.profile.agentMemory.activeModule = "Healthcare";
  db.profile.agentMemory.lastRecommendedSection = "health";
  db.profile.agentMemory.lastStatus = "health-provider-guidance";
  db.profile.agentMemory.lastSummary = response;
  db.profile.agentMemory.updatedAt = new Date().toISOString();
  rememberAgentMemory(db.profile, `Health provider question: ${command}`, { source: "health-provider-advisor", module: "Healthcare", category: "question", confidence: 0.9 });
  logIntegration(db, {
    providerId: "openai",
    module: "Healthcare",
    action: "agent.health_provider_guidance",
    detail: response.slice(0, 240),
    metadata: { provider, command, country: country.name },
    dispatch: false
  });
  return {
    intent: "health.provider_guidance",
    status: "completed",
    response,
    metadata: {
      conversationMode: true,
      redirectSection: "health",
      provider,
      suggestedReplies: ["find a clinic near me", "start telehealth intake", "find pharmacy support", "show urgent warning signs"]
    }
  };
}

function isCareerPathQuestion(command = "") {
  const lower = String(command || "").toLowerCase().trim();
  if (!lower) return false;
  const educationSignal = /\b(graduated|graduate|degree|university|college|diploma|certificate|studied|study|biochemistry|biology|chemistry|laboratory|lab)\b/.test(lower);
  const workSignal = /\b(job|jobs|career|apply|work|role|roles|hiring|opportunities|employment|profession|kenya|south africa|nigeria|ghana|rwanda|tanzania|egypt)\b/.test(lower);
  return educationSignal && workSignal;
}

