function knownMapLocation(query = "", fallbackCountry = null) {
  const value = String(query || "").toLowerCase();
  const known = [
    { keys: ["lagos"], label: "Lagos, Nigeria", lat: 6.5244, lng: 3.3792, country: "Nigeria" },
    { keys: ["nigeria"], label: "Nigeria", lat: 9.082, lng: 8.6753, country: "Nigeria" },
    { keys: ["nairobi"], label: "Nairobi, Kenya", lat: -1.2921, lng: 36.8219, country: "Kenya" },
    { keys: ["kenya"], label: "Kenya", lat: -0.0236, lng: 37.9062, country: "Kenya" },
    { keys: ["kinshasa"], label: "Kinshasa, DRC", lat: -4.4419, lng: 15.2663, country: "DRC" },
    { keys: ["congo", "drc"], label: "Democratic Republic of the Congo", lat: -2.8799, lng: 23.656, country: "DRC" },
    { keys: ["cairo"], label: "Cairo, Egypt", lat: 30.0444, lng: 31.2357, country: "Egypt" },
    { keys: ["egypt"], label: "Egypt", lat: 26.8206, lng: 30.8025, country: "Egypt" },
    { keys: ["accra"], label: "Accra, Ghana", lat: 5.6037, lng: -0.187, country: "Ghana" },
    { keys: ["ghana"], label: "Ghana", lat: 7.9465, lng: -1.0232, country: "Ghana" },
    { keys: ["kigali"], label: "Kigali, Rwanda", lat: -1.9441, lng: 30.0619, country: "Rwanda" },
    { keys: ["rwanda"], label: "Rwanda", lat: -1.9403, lng: 29.8739, country: "Rwanda" },
    { keys: ["dar es salaam", "tanzania"], label: "Tanzania", lat: -6.369, lng: 34.8888, country: "Tanzania" },
    { keys: ["johannesburg", "south africa"], label: "South Africa", lat: -30.5595, lng: 22.9375, country: "South Africa" }
  ];
  const found = known.find(item => item.keys.some(key => value.includes(key)));
  if (found) return found;
  if (fallbackCountry) return { label: fallbackCountry.name, lat: fallbackCountry.lat, lng: fallbackCountry.lng, country: fallbackCountry.name };
  return null;
}

function extractTradeRouteLocations(text = "", country = null) {
  const value = String(text || "").replace(/\s+/g, " ").trim();
  const buyerMatch = value.match(/\b(?:buyer|customer|purchaser|client)\b.*?\b(?:in|at|near|around|to|from)\s+([^,.]+(?:,\s*[^,.]+)?)/i);
  const sellerMatch = value.match(/\b(?:i am|i'm|we are|seller is|farmer is|pickup is|origin is|from)\s+(?:in|at|near|around)?\s*([^,.]+(?:,\s*[^,.]+)?)/i);
  const toMatch = value.match(/\b(?:to|deliver to|ship to|send to)\s+([^,.]+(?:,\s*[^,.]+)?)/i);
  const fromMatch = value.match(/\b(?:from|pickup from|ship from|origin)\s+([^,.]+(?:,\s*[^,.]+)?)/i);
  const destinationText = (buyerMatch?.[1] || toMatch?.[1] || "buyer location").trim();
  const originText = (sellerMatch?.[1] || fromMatch?.[1] || country?.name || "seller location").trim();
  return {
    originText,
    destinationText,
    origin: knownMapLocation(originText, country),
    destination: knownMapLocation(destinationText, country)
  };
}

function isBuyerSellerLocationRouteCommand(lower = "") {
  const value = String(lower || "");
  const hasBuyerOrSeller = /\b(buyer|customer|purchaser|client|seller|farmer|pickup|delivery address|buyer address|seller address)\b/.test(value);
  const hasLocationPair = /\b(lagos|kenya|nairobi|address|buyer location|seller location|pickup location|delivery location)\b/.test(value)
    || /\b(i am|i'm|we are|seller is|farmer is|pickup is)\b.*\b(in|at|near|around)\b/.test(value);
  const hasRouteAction = /\b(route|map|track|tracking|where|deliver|delivery|purchased|bought|sold|ship|shipment)\b/.test(value);
  return hasBuyerOrSeller && hasLocationPair && hasRouteAction;
}

function isTradeCountryRouteCommand(lower = "") {
  const value = String(lower || "");
  const hasTradeRoute = /\b(trade|crop|shipment|delivery|seller|buyer|market|logistics)\b.*\b(route|map|tracking|track|path|corridor)\b/.test(value)
    || /\b(route|map|tracking|track|path|corridor)\b.*\b(trade|crop|shipment|delivery|seller|buyer|market|logistics)\b/.test(value);
  const hasFromTo = /\bfrom\s+[^,.]+\s+\bto\s+[^,.]+/.test(value) || /\bbetween\s+[^,.]+\s+\band\s+[^,.]+/.test(value);
  const hasKnownPlaces = /\b(nigeria|kenya|lagos|nairobi|drc|congo|egypt|ghana|rwanda|tanzania|south africa|cairo|accra|kigali|kinshasa)\b/.test(value);
  return hasTradeRoute && hasFromTo && hasKnownPlaces;
}

function distanceKmBetween(a, b) {
  if (!a || !b || !Number.isFinite(Number(a.lat)) || !Number.isFinite(Number(b.lat))) return null;
  const radius = 6371;
  const toRad = value => Number(value) * Math.PI / 180;
  const dLat = toRad(b.lat - a.lat);
  const dLng = toRad(b.lng - a.lng);
  const lat1 = toRad(a.lat);
  const lat2 = toRad(b.lat);
  const h = Math.sin(dLat / 2) ** 2 + Math.cos(lat1) * Math.cos(lat2) * Math.sin(dLng / 2) ** 2;
  return Math.round(radius * 2 * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h)));
}

function tradeLocationRouteResponse(db, user, text, options = {}) {
  ensureAiProfile(db.profile);
  ensureTradeProfile(db.profile);
  const { country, route } = activeContext(db);
  const locations = extractTradeRouteLocations(text, country);
  const product = (db.products || []).find(item => item.countryId === country.id) || (db.products || [])[0];
  const order = latestRecordByDate(db.profile.orders || [], ["createdAt", "updatedAt"]);
  const origin = locations.origin || knownMapLocation(locations.originText, country);
  const destination = locations.destination || knownMapLocation(locations.destinationText, country);
  const distanceKm = distanceKmBetween(origin, destination);
  const mapProvider = runtimeProviderById(db, "maps") || runtimeProviderById(db, "map-tiles");
  const logisticsProvider = runtimeProviderById(db, "trade-logistics");
  const liveRoutingConfigured = Boolean(process.env.ROUTING_WEBHOOK_URL || process.env.MAPBOX_ACCESS_TOKEN || process.env.OPENROUTESERVICE_API_KEY || process.env.GOOGLE_MAPS_API_KEY);
  const packet = {
    id: crypto.randomUUID(),
    packetNumber: `LOCATION-ROUTE-${String((db.profile.locationRoutePackets || []).length + 1).padStart(3, "0")}`,
    productName: order?.productName || order?.product || product?.name || "crop lot",
    buyerLocation: locations.destinationText,
    sellerLocation: locations.originText,
    origin,
    destination,
    distanceKm,
    routeId: route.id,
    routeName: route.name,
    checkpoint: db.profile.activeCheckpoint || route.checkpoints?.[0] || "",
    providerStatus: liveRoutingConfigured ? "live-routing-provider-configured" : "provider-ready-routing",
    mapProviderStatus: mapProvider?.status || "provider-ready",
    logisticsProviderStatus: logisticsProvider?.status || "provider-ready",
    nextSteps: [
      "Confirm seller pickup address.",
      "Confirm buyer delivery address.",
      "Attach the crop order or create one.",
      "Run route risk and weather check.",
      "Share tracking update with buyer by WhatsApp, SMS, phone, or in-app chat."
    ],
    createdBy: user?.email || "Ask Nexus",
    createdAt: new Date().toISOString()
  };
  db.profile.locationRoutePackets.unshift(packet);
  db.profile.locationRoutePackets = db.profile.locationRoutePackets.slice(0, 20);
  addMapInsight(db.profile, {
    type: "map.buyer_seller_location_route",
    label: `${packet.productName} route from ${packet.sellerLocation} to ${packet.buyerLocation}`,
    detail: distanceKm
      ? `Provider-ready route packet created for ${packet.productName}: ${packet.sellerLocation} to ${packet.buyerLocation}, about ${distanceKm} km direct distance.`
      : `Provider-ready route packet created for ${packet.productName}: ${packet.sellerLocation} to ${packet.buyerLocation}.`,
    routeName: route.name,
    checkpoint: packet.checkpoint
  });
  logIntegration(db, {
    providerId: "maps",
    module: "Maps",
    action: "map.buyer_seller_location_route",
    detail: `${packet.packetNumber} created from ${packet.sellerLocation} to ${packet.buyerLocation}.`,
    metadata: { packetId: packet.id, origin, destination, distanceKm, liveRoutingConfigured },
    dispatch: false
  });
  rememberAgentMemory(db.profile, `Buyer route created from ${packet.sellerLocation} to ${packet.buyerLocation} for ${packet.productName}.`, { source: "buyer-location-route", category: "pattern", module: "Maps", confidence: 0.91 });
  return {
    intent: "map.buyer_seller_location_route",
    response: distanceKm
      ? `I created the route packet for ${packet.productName}: seller pickup ${packet.sellerLocation}, buyer delivery ${packet.buyerLocation}. Direct distance is about ${distanceKm} kilometers. I opened the map so you can review route risk, shipment tracking, buyer updates, and delivery evidence. Live turn-by-turn routing will use Mapbox, Google Maps, or OpenRouteService when credentials are connected.`
      : `I created the route packet for ${packet.productName}: seller pickup ${packet.sellerLocation}, buyer delivery ${packet.buyerLocation}. I opened the map so you can review route risk, shipment tracking, buyer updates, and delivery evidence. Add a full address or routing provider for exact turn-by-turn distance.`,
    status: "completed",
    metadata: {
      conversationMode: true,
      redirectSection: "map",
      packet,
      providerReady: true,
      liveRoutingConfigured,
      suggestedReplies: ["run route risk", "message buyer", "track my route in real time", "create order"]
    }
  };
}

function nexusMissionBrainModel(db, user, goalText = "", options = {}) {
  ensureAiProfile(db.profile);
  ensureLearningProfile(db.profile);
  ensureWorkforceProfile(db.profile);
  ensureHealthProfile(db.profile);
  ensureTradeProfile(db.profile);
  const goal = String(goalText || "Run the best AgriNexus mission from the current platform context.").trim();
  const providers = runtimeProviders(db);
  const { country, route } = activeContext(db);
  const signal = conversationModuleSignal(goal);
  const memories = retrieveAgentMemories(db.profile, goal, 6);
  const smart = smartNextActions(db, user, providers);
  const autopilot = buildAutopilotPlan(db, goal, user);
  const latestRoutePacket = (db.profile.locationRoutePackets || [])[0] || null;
  const liveProviders = providers.filter(provider => provider.status === "connected");
  const providerReady = providers.filter(provider => provider.status !== "connected");
  const risky = /\b(health|injury|emergency|doctor|provider|payment|wallet|buyer|seller|route|delivery|shipment|job|apply|message|call|whatsapp|sms)\b/i.test(goal);
  const role = user?.role || "User";
  const roleFrame = role === "Admin"
    ? "operations, provider health, failure recovery, and audit evidence"
    : role === "Investor"
      ? "impact, scale readiness, proof, and pilot story"
      : "simple guided help, voice-first steps, and low-tech usability";
  const confidence = Math.min(0.97, Math.max(0.72,
    0.62
    + (signal.score || 0) * 0.18
    + (memories.length ? 0.06 : 0)
    + (latestRoutePacket ? 0.04 : 0)
    + (liveProviders.length ? 0.03 : 0)
  ));
  const nextActions = smart.items.slice(0, 5).map(item => ({
    title: item.title,
    module: item.module,
    section: item.section,
    reason: item.reason || item.detail,
    command: item.command || item.title
  }));
  const missionSteps = autopilot.steps.slice(0, 8).map((step, index) => ({
    order: index + 1,
    module: step.module,
    tool: step.tool,
    action: step.action,
    status: "planned",
    confirmationRequired: /health|payment|buyer|message|provider|apply|route/i.test(`${step.module} ${step.tool} ${step.action}`)
  }));
  const alerts = [];
  if (!(db.profile.healthIntakes || []).length) alerts.push({ module: "Healthcare", priority: "medium", message: "No active health intake exists; start intake before care routing." });
  if ((db.profile.orders || []).length && !(db.profile.tradeMessageThreads || []).length) alerts.push({ module: "AgriTrade", priority: "high", message: "A trade order needs buyer-seller communication evidence." });
  if ((db.profile.orders || []).length && !(db.profile.locationRoutePackets || []).length) alerts.push({ module: "Maps", priority: "medium", message: "A trade order needs buyer/seller route evidence." });
  if (!liveProviders.some(provider => provider.id === "openai")) alerts.push({ module: "AI", priority: "medium", message: "Live OpenAI is not connected in this runtime; local reasoning remains active." });
  if (!liveProviders.some(provider => provider.id === "maps" || provider.id === "map-tiles")) alerts.push({ module: "Maps", priority: "medium", message: "Live map/routing credentials improve address geocoding, ETA, and traffic." });
  const layers = [
    { id: "context-awareness", title: "True Context Awareness", active: true, evidence: `${signal.module || "Platform"} matched; active country ${country.name}; route ${route.name}.` },
    { id: "live-provider-reasoning", title: "Live Provider Reasoning", active: true, evidence: `${liveProviders.length}/${providers.length} provider adapter(s) connected; ${providerReady.length} provider-ready.` },
    { id: "multi-step-mission-planning", title: "Multi-Step Mission Planning", active: true, evidence: `${missionSteps.length} planned step(s) from current goal.` },
    { id: "proactive-alerts", title: "Proactive Alerts", active: true, evidence: `${alerts.length} active alert(s) generated from platform state.` },
    { id: "personal-memory", title: "Personal Memory", active: true, evidence: `${memories.length} relevant memory cue(s) retrieved.` },
    { id: "voice-clarification", title: "Voice Clarification", active: true, evidence: "One-question clarification and imperfect speech repair are available before risky actions." },
    { id: "decision-scoring", title: "Decision Scoring", active: true, evidence: `${Math.round(confidence * 100)}% confidence for this mission plan.` },
    { id: "real-time-map-intelligence", title: "Real-Time Map Intelligence", active: true, evidence: latestRoutePacket ? `Latest route packet ${latestRoutePacket.packetNumber}: ${latestRoutePacket.sellerLocation} to ${latestRoutePacket.buyerLocation}.` : "Map route packets, GPS route tracking, weather, and provider-ready routing are available." },
    { id: "role-based-intelligence", title: "Role-Based Intelligence", active: true, evidence: `${role} mode focuses on ${roleFrame}.` },
    { id: "safety-compliance-brain", title: "Safety And Compliance Brain", active: true, evidence: risky ? "This mission touches sensitive health, buyer, payment, provider, job, route, or messaging actions; confirmation is required." : "No high-risk action detected; standard confirmation remains available." }
  ];
  const brain = {
    id: crypto.randomUUID(),
    mode: "nexus-mission-brain",
    goal,
    status: risky ? "planned-needs-confirmation" : "planned-ready",
    confidence: Number(confidence.toFixed(2)),
    activeContext: {
      country: country.name,
      route: route.name,
      checkpoint: db.profile.activeCheckpoint || route.checkpoints?.[0] || "",
      detectedModule: signal.module || "Platform",
      section: signal.section || sectionForAgentModule(signal.module || "Platform")
    },
    layers,
    nextActions,
    missionSteps,
    proactiveAlerts: alerts.slice(0, 6),
    memoryUsed: memories.map(item => ({
      id: item.id,
      category: item.category,
      module: item.module,
      text: item.text || item.event || item.response || item.command,
      confidence: item.confidence
    })),
    providerTruth: {
      connected: liveProviders.map(provider => provider.id),
      providerReady: providerReady.map(provider => provider.id).slice(0, 18),
      rule: "Mission Brain must say what is live, local, provider-ready, or waiting on credentials."
    },
    mapIntelligence: {
      routePacket: latestRoutePacket,
      gpsTrackingReady: true,
      liveRoutingReady: Boolean(process.env.ROUTING_WEBHOOK_URL || process.env.MAPBOX_ACCESS_TOKEN || process.env.OPENROUTESERVICE_API_KEY || process.env.GOOGLE_MAPS_API_KEY),
      weatherLocationReady: true
    },
    roleBehavior: {
      role,
      frame: roleFrame,
      userModeRule: "Keep the user experience simple, guided, visual, and voice-first.",
      adminModeRule: "Expose operational evidence, provider failures, and recovery next steps.",
      investorModeRule: "Explain impact, proof, scalability, and live-provider gaps."
    },
    safety: {
      confirmationRequired: risky,
      boundaries: [
        "Do not diagnose medical conditions.",
        "Confirm before health, payment, job application, buyer contact, provider contact, or route-changing actions.",
        "Use emergency guidance for danger signs.",
        "Say when data is local context instead of live provider data."
      ]
    },
    suggestedCommands: [
      "Nexus, run the first mission step",
      "Nexus, explain the mission",
      "Nexus, track the buyer route",
      "Nexus, message the buyer",
      "Nexus, start telehealth intake"
    ],
    createdBy: user?.email || "Ask Nexus",
    createdAt: new Date().toISOString()
  };
  db.profile.missionBrainRuns.unshift(brain);
  db.profile.missionBrainRuns = db.profile.missionBrainRuns.slice(0, 20);
  db.profile.agentMemory.activeMissionBrain = brain;
  db.profile.agentMemory.lastStatus = "mission-brain-ready";
  db.profile.agentMemory.lastSummary = `Mission Brain planned ${missionSteps.length} step(s) with ${Math.round(confidence * 100)}% confidence.`;
  db.profile.agentMemory.updatedAt = brain.createdAt;
  rememberAgentMemory(db.profile, `Mission Brain goal: ${goal}. Next action: ${nextActions[0]?.title || "continue guided mission"}.`, { source: "nexus-mission-brain", category: "pattern", module: signal.module || "Agent AI", confidence: 0.93 });
  logIntegration(db, {
    providerId: "openai",
    module: "Agent AI",
    action: "agent.mission_brain_planned",
    detail: `Mission Brain planned ${missionSteps.length} step(s) for ${goal}.`,
    metadata: { brainId: brain.id, confidence: brain.confidence, layers: layers.map(layer => layer.id), alerts: alerts.length },
    dispatch: false
  });
  return brain;
}

function missionBrainCommandResponse(db, user, text, options = {}) {
  const brain = nexusMissionBrainModel(db, user, text, options);
  const first = brain.nextActions[0] || brain.missionSteps[0] || null;
  return {
    intent: "agent.mission_brain",
    response: `Nexus Mission Brain is active. I read the goal, checked context, memory, providers, map intelligence, safety, role mode, and next actions. Confidence is ${Math.round(brain.confidence * 100)}%. I planned ${brain.missionSteps.length} step(s), found ${brain.proactiveAlerts.length} alert(s), and ${brain.safety.confirmationRequired ? "will require confirmation before sensitive actions" : "can guide the next low-risk step"}. Recommended next step: ${first?.title || first?.action || "continue guided mission"}.`,
    status: brain.status,
    metadata: {
      conversationMode: true,
      redirectSection: brain.activeContext.section || "agent",
      missionBrain: brain,
      suggestedReplies: brain.suggestedCommands
    }
  };
}

function nexusTrustedOperatingSystemModel(db, user, goalText = "", options = {}) {
  ensureAiProfile(db.profile);
  ensureLearningProfile(db.profile);
  ensureWorkforceProfile(db.profile);
  ensureHealthProfile(db.profile);
  ensureTradeProfile(db.profile);
  ensureOperationsProfile(db.profile);
  const providers = runtimeProviders(db);
  const readiness = productionReadiness(providers);
  const operations = productionOperationsPlan(db, providers);
  const completeness = productionCompleteness(db, providers);
  const missionBrain = db.profile.agentMemory.activeMissionBrain || nexusMissionBrainModel(db, user, goalText || "trusted operating system review", options);
  const permissions = permissionsForRole(user?.role || "User");
  const connectedProviders = providers.filter(provider => provider.status === "connected");
  const providerReady = providers.filter(provider => provider.status !== "connected");
  const auditEvents = db.profile.integrationEvents || [];
  const agentCommands = db.profile.agentCommands || [];
  const workflowEvidence = [
    (db.profile.enrollments || []).length,
    (db.profile.applications || []).length,
    (db.profile.healthIntakes || []).length,
    (db.profile.orders || []).length,
    (db.profile.droneScans || []).length,
    (db.profile.mapInsights || []).length,
    auditEvents.length,
    agentCommands.length
  ].reduce((sum, value) => sum + Number(value || 0), 0);
  const hasVoice = Boolean((db.profile.voiceSessions || []).length || process.env.OPENAI_API_KEY || process.env.VOICE_TTS_PROVIDER || process.env.VOICE_STT_PROVIDER);
  const hasTranslation = connectedProviders.some(provider => provider.id === "translation") || ["en", "fr", "sw", "ar", "es"].includes(user?.language || db.profile.accessibilityProfile?.language || "en");
  const hasMap = Boolean((db.profile.locationRoutePackets || []).length || connectedProviders.some(provider => provider.id === "maps" || provider.id === "map-tiles"));
  const hasSafety = Boolean(fs.existsSync(path.join(PUBLIC, "terms.html")) && fs.existsSync(path.join(PUBLIC, "privacy.html")));
  const pillars = [
    { id: "reliable-workflows", title: "Reliable Workflows", ready: workflowEvidence >= 8, evidence: `${workflowEvidence} workflow/evidence record(s) across learning, workforce, health, trade, drone, map, AI, and audit.` },
    { id: "provider-truth", title: "Provider Truth", ready: true, evidence: `${connectedProviders.length}/${providers.length} provider adapter(s) connected; Nexus distinguishes live, local, and provider-ready.` },
    { id: "safety-guardrails", title: "Safety Guardrails", ready: hasSafety, evidence: hasSafety ? "Legal pages, telehealth guardrails, emergency language, and confirmation gates are present." : "Terms/Privacy or final legal review still need production confirmation." },
    { id: "role-permissions", title: "Role Permissions", ready: Boolean(permissions && Object.keys(permissions).length), evidence: `${user?.role || "User"} mode permits ${Object.entries(permissions).filter(([, allowed]) => allowed).map(([key]) => key).join(", ") || "restricted access"}.` },
    { id: "memory-and-context", title: "Memory And Context", ready: Boolean((db.profile.agentMemory?.preferences || []).length || (db.profile.agentConversation || []).length || missionBrain), evidence: `${(db.profile.agentConversation || []).length} conversation turn(s), ${(db.profile.agentMemory?.memoryTimeline || []).length} memory timeline event(s), Mission Brain ${missionBrain?.status || "ready"}.` },
    { id: "multilingual-voice", title: "Multilingual Voice", ready: hasVoice && hasTranslation, evidence: `Voice sessions ${(db.profile.voiceSessions || []).length}; translation path ${hasTranslation ? "available" : "needs provider"}.` },
    { id: "map-location-intelligence", title: "Map And Location Intelligence", ready: hasMap, evidence: `${(db.profile.locationRoutePackets || []).length} route packet(s), ${(db.profile.mapInsights || []).length} map insight(s), GPS/weather handoff ready.` },
    { id: "auditability", title: "Auditability", ready: auditEvents.length >= 8, evidence: `${auditEvents.length} integration/audit event(s), ${agentCommands.length} agent command record(s).` },
    { id: "failure-recovery", title: "Failure Recovery", ready: true, evidence: "Timeout fallback, voice stop, clarification repair, local context fallback, and provider-ready messaging are active." },
    { id: "production-hardening", title: "Production Hardening", ready: operations.readyCount >= Math.ceil(operations.total * 0.7), evidence: `${operations.readyCount}/${operations.total} production workstream(s) ready; completeness ${completeness.readyCount}/${completeness.total}.` }
  ];
  const readyCount = pillars.filter(pillar => pillar.ready).length;
  const score = Math.round((readyCount / pillars.length) * 100);
  const gaps = [
    ...operations.nextSteps.slice(0, 5),
    ...completeness.nextSteps.slice(0, 4)
  ].filter(Boolean).slice(0, 8);
  const review = {
    id: crypto.randomUUID(),
    mode: "nexus-trusted-operating-system",
    status: score >= 90 ? "trusted-operational" : score >= 75 ? "trusted-provider-ready" : "trusted-hardening",
    score,
    readyCount,
    total: pillars.length,
    goal: goalText || "Make AgriNexus a trusted operating system people can rely on.",
    pillars,
    reliabilityContract: [
      "Nexus must tell users what is live, local, provider-ready, or unavailable.",
      "Nexus must ask for confirmation before health, payment, buyer, provider, job, route, or messaging actions.",
      "Nexus must create audit evidence for meaningful workflow actions.",
      "Nexus must recover from unclear speech with one simple question.",
      "Nexus must keep User mode simple and protect Admin-only controls."
    ],
    providerTruth: {
      connected: connectedProviders.map(provider => provider.id),
      providerReady: providerReady.map(provider => provider.id).slice(0, 18),
      liveGaps: readiness.nextSteps.slice(0, 8)
    },
    roleTrust: {
      role: user?.role || "User",
      permissions,
      userRule: "Simple, guided, voice-first workflows.",
      adminRule: "Operational control, provider health, audit evidence, and user management.",
      investorRule: "Impact story, proof, readiness, and provider gaps without exposing admin controls."
    },
    recoveryModel: {
      stopCommand: "Nexus stop",
      unclearSpeech: "Ask one plain-language question.",
      providerFailure: "Use local workflow evidence and say the provider is not live.",
      safetyEscalation: "Urgent health danger signs route to emergency guidance and human/provider support.",
      offlineOrSlowNetwork: "Keep app workflow and evidence local until sync/provider return."
    },
    missionBrain: {
      id: missionBrain?.id || null,
      status: missionBrain?.status || "not-started",
      confidence: missionBrain?.confidence || 0,
      nextAction: missionBrain?.nextActions?.[0]?.title || missionBrain?.missionSteps?.[0]?.action || "Ask Nexus for a mission"
    },
    nextGaps: gaps.length ? gaps : ["No code gap detected; next improvement is live provider credentials and field testing."],
    createdBy: user?.email || "Ask Nexus",
    createdAt: new Date().toISOString()
  };
  db.profile.trustedOsReviews.unshift(review);
  db.profile.trustedOsReviews = db.profile.trustedOsReviews.slice(0, 20);
  db.profile.agentMemory.lastTrustedOperatingSystem = review;
  db.profile.agentMemory.lastStatus = "trusted-os-reviewed";
  db.profile.agentMemory.lastSummary = `Trusted OS score ${score}% with ${readyCount}/${pillars.length} pillars ready.`;
  db.profile.agentMemory.updatedAt = review.createdAt;
  rememberAgentMemory(db.profile, `Trusted OS review: ${score}% score, ${readyCount}/${pillars.length} pillars ready.`, { source: "trusted-operating-system", category: "pattern", module: "Platform", confidence: 0.94 });
  logIntegration(db, {
    providerId: "openai",
    module: "Agent AI",
    action: "agent.trusted_os_reviewed",
    detail: `Trusted OS review scored ${score}% with ${readyCount}/${pillars.length} pillars ready.`,
    metadata: { reviewId: review.id, score, readyCount, total: pillars.length, status: review.status },
    dispatch: false
  });
  return review;
}

function trustedOperatingSystemCommandResponse(db, user, text, options = {}) {
  const review = nexusTrustedOperatingSystemModel(db, user, text, options);
  const topGap = review.nextGaps[0] || "Keep testing with real users and live providers.";
  return {
    intent: "agent.trusted_operating_system",
    response: `Trusted Operating System review complete. AgriNexus is at ${review.score}% with ${review.readyCount}/${review.total} trust pillars ready. Status: ${review.status}. Nexus can be relied on for guided workflows, voice, memory, audit evidence, role permissions, safety guardrails, provider truth, and recovery behavior. The next trust gap is: ${topGap}`,
    status: review.status,
    metadata: {
      conversationMode: true,
      redirectSection: user?.role === "Admin" ? "admin" : user?.role === "Investor" ? "agent" : "dashboard",
      trustedOperatingSystem: review,
      suggestedReplies: ["activate mission brain", "run live service check", "what works without providers", "show next trust gap"]
    }
  };
}

function fahrenheitFromCelsius(celsius) {
  return Math.round((Number(celsius || 0) * 9 / 5) + 32);
}

function latestRecordByDate(items = [], dateKeys = ["startsAt", "createdAt", "scheduledAt"]) {
  return [...(items || [])]
    .filter(Boolean)
    .sort((a, b) => {
      const aTime = dateKeys.map(key => Date.parse(a?.[key] || "")).find(Number.isFinite) || 0;
      const bTime = dateKeys.map(key => Date.parse(b?.[key] || "")).find(Number.isFinite) || 0;
      return bTime - aTime;
    })[0] || null;
}

function nextRecordByDate(items = [], dateKeys = ["startsAt", "scheduledAt", "createdAt"]) {
  const now = Date.now();
  const dated = (items || []).map(item => {
    const time = dateKeys.map(key => Date.parse(item?.[key] || "")).find(Number.isFinite) || 0;
    return { item, time };
  }).filter(entry => entry.time);
  return (dated.filter(entry => entry.time >= now).sort((a, b) => a.time - b.time)[0]
    || dated.sort((a, b) => b.time - a.time)[0]
    || {}).item || null;
}

function extractTemperatureF(text) {
  const value = String(text || "");
  const fahrenheit = value.match(/\b(\d{2,3})\s*(?:degrees?|deg|f|fahrenheit)\b/i);
  if (fahrenheit?.[1]) return Number(fahrenheit[1]);
  const celsius = value.match(/\b(\d{1,2})\s*(?:c|celsius)\b/i);
  if (celsius?.[1]) return fahrenheitFromCelsius(Number(celsius[1]));
  return null;
}

